INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (2, 'active-communication-ag', 'Active Communication AG', 31, 'Die Stiftung für elektronische Hilfsmittel FST unterstützt und versorgt Menschen mit Behinderung seit über 30 Jahren schweizweit mit elektronischen Hilfsmitteln. Unser Ziel ist es, modernste Technologie in den Dienst von Menschen mit Behinderung zu stellen: Die Schwerpunkte unserer Arbeit liegen in den Bereichen Unterstützte Kommunikation, Computeranpassungen, Umweltkontrolle und Hilfen für Senioren.', 'Sumpfstrasse 28, 6312 Steinhausen, 041 747 03 03, office@activecommunication.ch, www.fst.ch', 'Sumpfstrasse 28, 6312 Steinhausen', '6312', 'Steinhausen', '["041 747 03 03"]', '["office@activecommunication.ch"]', '["activecommunication.ch", "www.fst.ch"]', 'Personen mit körperlicher und /oder geistiger Einschränkung  / Fachpersonen: Heilpädagogik, Logopädie, Sozialpädagogik, Agogik, Ergotherapie etc.', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Personen mit körperlicher und /oder geistiger Einschränkung  / Fachpersonen: Heilpädagogik, Logopädie, Sozialpädagogik, Agogik, Ergotherapie etc.", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (3, 'adele-koller-knusli-stiftung', 'Adele Koller-Knüsli Stiftung', 31, 'Unterstützung und Förderung von sozialen Projekten und Organisationen hauptsächlich im Raume Winterthur. Die zu erfüllenden Voraussetzung sind auf unserer Website zu finden.', 'c/o Marina Heusser, Hochwachtstrasse 16, 8400 Winterthur, 052 212 45 46, akk-stiftung@bluewin.ch, www.akk-stiftung.ch', 'c/o Marina Heusser, Hochwachtstrasse 16, 8400 Winterthur', '8400', 'Winterthur', '["052 212 45 46"]', '["akk-stiftung@bluewin.ch"]', '["bluewin.ch", "www.akk-stiftung.ch"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Ausländer/innen, Armut', 'Institutionen', '15.5./15.10.', NULL, 'Jahresbericht und Jahresrechnung, Revisionsbericht', '{"BEILAGEN": "Jahresbericht und Jahresrechnung, Revisionsbericht", "ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Ausländer/innen, Armut", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "15.5./15.10."}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (4, 'age-stiftung', 'AGE-Stiftung', 32, 'Die Age-Stiftung fokussiert das Thema Wohnen und Älterwerden in ihrem Wirkungsgebiet, der deutschsprachigen Schweiz. Jährlich investiert die Stiftung rund 3 Mio. Franken in Wohn-, Betreuungs- oder Dienstleistungsmodelle, welche neuartige Komponenten aufweisen und beispielhaft wirken können. Aus den geförderten Projekten sollen neue Erkenntnisse gewonnen werden. Deshalb findet man Dokumentationen und Kontaktangaben zu allen unterstützten Projekten unter www.age-stiftung.ch.', 'Kirchgasse 42, 8001 Zürich, 044 455 70 60, info@age-stiftung.ch, www.age-stiftung.ch', 'Kirchgasse 42, 8001 Zürich,, www.', '8001', 'Zürich', '["044 455 70 60"]', '["info@age-stiftung.ch"]', '["age-stiftung.ch", "www.age-stiftung.ch"]', NULL, 'Privatpersonen, Institutionen', 'Ganzes Jahr. Termine zweimal jährlich - siehe Website. Spezialformular anfordern', NULL, NULL, '{"GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Termine zweimal jährlich - siehe Website. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (5, 'albert-und-ida-beer-stiftung', 'Albert und Ida Beer Stiftung', 32, 'Förderung und Unterstützung schweizerischer Institutionen gemeinnützigen Charakters, vorwiegend im Kanton Zürich, sowie die Unterstützung bedürftiger im Kanton Zürich wohnhafter Einzelpersonen.', 'c/o Schwarzmann Brändli Rechtsanwälte, Theaterstrasse 2, Postfach 163, 8024 Zürich, 044 261 91 00, sts@sts-law.ch', 'c/o Schwarzmann Brändli Rechtsanwälte, Theaterstrasse 2, Postfach 163, 8024 Zürich', '8024', 'Zürich', '["044 261 91 00"]', '["sts@sts-law.ch"]', '["sts-law.ch"]', 'Bedürftige, gemeinnützige Institutionen', 'Privatpersonen, Institutionen', 'Jederzeit. Gesuche werden nur von öffentlichen und privaten Fürsorgestellen mit dem offiziellen Formular des kantonalen Amtes für Jugend- und Berufsberatung und den üblichen Unterlagen entgegengenommen. Spezialformular anfordern', 'Albert und Ida Beer Stiftung
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (11, 'boniger-kramer-stiftung', 'Böniger-Kramer-Stiftung', 35, 'Unterstützung bedürftiger Evangelisch-Reformierter in der Schweiz, Beiträge an die Berghilfe und an evangelisch-reformierte Diaspora-Gemeinden, jährliche Zuschüsse für die Unterstützung von reformierten Armen der Gemeinde Rüti ZH, Zuschüsse an das HEKS für spezielle Hilfe an notleidenden Protestanten, Zuschüsse an die Waldenser und Pro Infirmis, für Gebrechliche, sowie materielle Hilfe an spätberufene Kandidaten für das evangelisch-reformierte Pfarramt, die aus andern Berufen stammen und Theologie studieren.', 'c/o WildbachPartner AG, Wildbachstrasse 46, 8034 Zürich, 044 387 52 00', 'c/o WildbachPartner AG, Wildbachstrasse 46, 8034 Zürich', '8034', 'Zürich', '["044 387 52 00"]', '[]', '[]', NULL, 'Privatpersonen', 'Ganzes Jahr', NULL, NULL, '{"GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
