INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (7, 'anna-caroline-stiftung', 'Anna Caroline Stiftung', 34, 'Die Stiftung gewährt im Rahmen ihrer finanziellen Möglichkeiten Frauen, die an schweizerischen Universitäten/ETH/EPFL (nicht an Fachhochschulen) studieren und finanzielle Schwierigkeiten haben, während der letzten zwei Semester bis zum Lizenziat oder Master Stipendien oder Darlehen bis zu Fr. 6000.-- pro Jahr. Unterstützt werden nur gut qualifizierte Studentinnen (Notendurchschnitt mindestens 4,5 bei 6 als Maximum). Ausländische Studentinnen werden nur in Ausnahmefällen berücksichtigt und nur dann, wenn sie schon seit mindestens fünf Jahren in der Schweiz leben und eine enge Beziehung zur Schweiz pflegen.', 'c/o ETH Zürich Foundation, Weinbergstrasse 29, 8006 Zürich, 044 633 69 55, info@annacaroline.ch, www.annacaroline.ch', 'c/o ETH Zürich Foundation, Weinbergstrasse 29, 8006 Zürich,, www.', '8006', 'Zürich', '["044 633 69 55"]', '["info@annacaroline.ch"]', '["annacaroline.ch", "www.annacaroline.ch"]', 'Jugend & Familie, Ausbildung, Frauen an der Universität/ETH (nicht Fachhochschulen)', 'Privatpersonen', 'Ende April, Ende Oktober. Spezialformular anfordern', NULL, 'Ausbildungsbestätigung, Beilagen gemäss unserem Formular auf der Website.', '{"BEILAGEN": "Ausbildungsbestätigung, Beilagen gemäss unserem Formular auf der Website.", "ZIELGRUPPE": "Jugend & Familie, Ausbildung, Frauen an der Universität/ETH (nicht Fachhochschulen)", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ende April, Ende Oktober. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (8, 'anna-maria-und-karl-kramer-stiftung', 'Anna Maria und Karl Kramer-Stiftung', 34, 'Förderung des Baurechts zwecks Vermeidung von Spekulation mit Grund und Boden. Die Stiftung übernimmt dafür Grundstücke und Liegenschaften. Baurechtszinsen und Kapitalertrag werden für Unterstützungsbeiträge eingesetzt. Berücksichtigt werden insbesondere kleinere Projekte im Bereich Soziales, Gesellschaftliches, Ökologie, Kultur. Keine Einzelfallhilfen.', 'Röslistrasse 2, 8006 Zürich, nellinaef@bluewin.ch, www.kramer-stiftung.ch', 'Röslistrasse 2, 8006 Zürich', '8006', 'Zürich', '[]', '["nellinaef@bluewin.ch"]', '["bluewin.ch", "www.kramer-stiftung.ch"]', 'Beiträge an kleinere Institutionen, die sozial, gemeinnützig, kulturell oder ökologisch schwergewichtig in der Schweiz tätig sind, v.a. innovative Projekte mit nachhaltiger Wirkung.
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (9, 'anna-und-paul-bucher-gossweiler-stiftung', 'Anna und Paul Bucher-Gossweiler-Stiftung', 34, 'Zweck der Stiftung ist es, zugunsten der bäuerlichen Bevölkerung der Gemeinnützigkeit zu dienen und deren Bestreben zu fördern und zu unterstützen. In erster Linie sollen landwirtschaftliches Dienstpersonal, das durch Alter, Krankheit, Invalidität oder sonstwie in der Erwerbsfähigkeit beschränkt ist sowie frühere selbstständige Landwirte, betagte und bedürftige Kleinbauern und deren Familien, die durch unverschuldete Ereignisse in Bedrängnis geraten sind, unterstützt werden.', 'c/o Rolf Gerber, Hüttenkopfstrasse 17, 8051 Zürich, www.bucher-gossweiler-stiftung.ch', 'c/o Rolf Gerber, Hüttenkopfstrasse 17, 8051 Zürich', '8051', 'Zürich', '[]', '[]', '["www.bucher-gossweiler-stiftung.ch"]', 'Armut', 'Privatpersonen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, Referenzen, Steuererklärungen, eventuell Bericht des Betriebsberaters', '{"BEILAGEN": "Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, Referenzen, Steuererklärungen, eventuell Bericht des Betriebsberaters", "ZIELGRUPPE": "Armut", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (10, 'august-weidmann-fursorge-stiftung', 'August Weidmann Fürsorge-Stiftung', 35, 'Die Stiftung bezweckt, unverschuldet in eine Notlage geratenen Personen, vornehmlich solchen mit einem Bezug zum Kanton Zürich, durch einmalige oder wiederholte Zuschüsse zu helfen sowie gemeinnützige Institutionen zu unterstützen, die solche Personen betreuen. Insbesondere sind betagte Bedürftige sowie in bescheidenen Verhältnissen lebende körperlich oder geistig Menschen mit Behinderungen Jugendliche und Erwachsene zu berücksichtigen. Im Weiteren kann die Stiftung Unterstützungsgesuche von rechtschaffenen Personen und Familien bewilligen, deren Lebenslos durch finanzielle Beiträge erleichtert und verbessert werden kann.', 'c/o Bruno Kläusli, Seestrasse 95, 8800 Thalwil, 044 720 01 07, info@august-weidmann.ch, www.august-weidmann.ch', 'c/o Bruno Kläusli, Seestrasse 95, 8800 Thalwil,, www.', '8800', 'Thalwil', '["044 720 01 07"]', '["info@august-weidmann.ch"]', '["august-weidmann.ch", "www.august-weidmann.ch"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen mit Niederlassungsbewilligung, Ausbildung, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', 'Gesuche in schriftlicher Form per Post an:
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (12, 'buchmann-kollbrunner-stiftung', 'Buchmann-Kollbrunner-Stiftung', 36, 'Die Stiftung bezweckt vorrangig die Unterstützung von körperlich oder geistig Menschen mit Behinderungenn Personen und von Institutionen, die sich für Menschen mit Behinderungen einsetzen. Die Stiftung leistet Einzelfallhilfe, unterstützt jedoch auch Projekte. Der Schwerpunkt der Tätigkeit liegt im Kanton Zürich, ausserkantonale Gesuche werden nur im Ausnahmefall behandelt. Gesuche durch anerkannte Institutionen (Pro Infirmis, Sozialhilfestellen usw.) werden bevorzugt. 
