INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (14, 'cassinelli-vogel-stiftung', 'Cassinelli-Vogel-Stiftung', 37, 'Einmalige Beiträge zur Überbrückung vorübergehender Notlagen, falls Staat und Gemeinde keine Unterstützung gewähren. Es sollen die Gesuchsformulare des Amts für Jugend und Berufsberatung verwendet werden. Stipendien werden nur in Ausnahmefällen gewährt. Wohnsitz: Kanton Zürich. Gesuche werden grundsätzlich nur von Institutionen entgegen genommen.', 'Volkmarstrasse 9, 8006 Zürich, 044 381 85 01, kontakt@cassinelli-vogel-stiftung.ch, www.cassinelli-vogel-stiftung.ch', 'Volkmarstrasse 9, 8006 Zürich,, www.', '8006', 'Zürich', '["044 381 85 01"]', '["kontakt@cassinelli-vogel-stiftung.ch"]', '["cassinelli-vogel-stiftung.ch", "www.cassinelli-vogel-stiftung.ch"]', 'Jugend, Familie, Betagte, Menschen mit Behinderungen, Kranke, Ausländer/innen, Armut, Ausbildung', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kontoangaben, Einzahlungsschein', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Einzahlungsschein", "ZIELGRUPPE": "Jugend, Familie, Betagte, Menschen mit Behinderungen, Kranke, Ausländer/innen, Armut, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (15, 'chana-lutomirsky-stiftung', 'Chana Lutomirsky Stiftung', 37, 'Finanzielle Unterstützung bedürftiger Insassen des Heims «Beth Chana» in Zürich durch Gewährung von Zuschüssen an die Kosten der Unterbringung und Betreuung im betreffenden Heim; finanzielle Unterstützung bedürftiger jüdischer Menschen mit Behinderungenr durch Gewährung von Beiträgen und Darlehen zur medizinischen Betreuung, Schulung und beruflichen sowie sozialen Eingliederung der Menschen mit Behinderungenn; finanzielle Unterstützung des Vereins für jüdische Menschen mit Behinderungen in der Schweiz durch Gewährung von Zuschüssen namentlich in Bezug auf die Führung und den Unterhalt des Heims «Beth Chana» in Zürich.', 'Bellerivestrasse 201, 8034 Zürich, 044 386 60 00, ehaymann@froriep.ch', 'Bellerivestrasse 201, 8034 Zürich', '8034', 'Zürich', '["044 386 60 00"]', '["ehaymann@froriep.ch"]', '["froriep.ch"]', 'Menschen mit Behinderungen', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Arztzeugnis, Kontoangaben', '{"BEILAGEN": "Arztzeugnis, Kontoangaben", "ZIELGRUPPE": "Menschen mit Behinderungen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (16, 'charles-e-blatter-stiftung', 'Charles E. Blatter-Stiftung', 37, 'Wohnraum für Studierende / Stipendien für Studierende an schweizerischen universitären Hochschulen; Karenzfrist: 2 Semester (Schweizer /-innen) respektive 4 Semester (Ausländer /-innen); nicht stipendiert werden Nachdiplomstudien / Zweitausbildungen / Weiterbildungsstudiengänge (CAS, DAS, MAS) / Dissertationen.', 'Stipendiensekretariat, c/o Frau E. Schniderlin, Gladbachstrasse 83, 8044 Zürich, schniderlin@gmail.com, www.blatterstiftung.ch', 'Stipendiensekretariat, c/o Frau E. Schniderlin, Gladbachstrasse 83, 8044 Zürich', '8044', 'Zürich', '[]', '["schniderlin@gmail.com"]', '["gmail.com", "www.blatterstiftung.ch"]', 'Studierende (Schweizer/innen und Ausländer/innen) an einer schweizerischen universitären Hochschule auf Bachelor- / Masterebene', 'Privatpersonen', 'Bis 30.06. für Herbstsemester / Bis 31.12. für Frühlingssemester. Erstgesuchsformular auf Homepage: www.blatterstiftung.ch', 'Frau E. Schniderlin, Stipendiensekretariat , Gladbachstrasse 83, 8044 Zürich', 'Ausbildungsbestätigung, Kontoangaben, Referenzen, CV / Halbjahresbudget / aktuelle Stipendienentscheide und Darlehenszusagen / letzte Steuerrechnung von Gesuchstellerin resp. -steller sowie deren/dessen Eltern', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen, CV / Halbjahresbudget / aktuelle Stipendienentscheide und Darlehenszusagen / letzte Steuerrechnung von Gesuchstellerin resp. -steller sowie deren/dessen Eltern", "ZIELGRUPPE": "Studierende (Schweizer/innen und Ausländer/innen) an einer schweizerischen universitären Hochschule auf Bachelor- / Masterebene", "EMPFANGSSTELLE": "Frau E. Schniderlin, Stipendiensekretariat , Gladbachstrasse 83, 8044 Zürich", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Bis 30.06. für Herbstsemester / Bis 31.12. für Frühlingssemester. Erstgesuchsformular auf Homepage: www.blatterstiftung.ch"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
