INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (18, 'deutscher-hilfsverein-zurich', 'Deutscher Hilfsverein Zürich', 38, 'Finanzielle Unterstützung für deutsche Staatsangehörige mit Aufenthaltsbewilligung B, C oder L und Wohnsitz in den Kantonen AG, AI, AR, BE, GL, GR, LU, SH, SZ, SO, SG, TG, UW, OW, UR, ZH, ZG oder dem FL. Der Deutsche Hilfsverein Zürich verlangt u.a. einen Nationalitätennachweis und detaillierte Angaben über die finanziellen Verhältnisse (Einnahmen, Ausgaben, Vermögen) möglichst mit Bestätigung durch die Fürsorgestelle der Wohngemeinde. Es werden keine Stipendien und keine Ausbildungshilfen gewährt. Anträge, die über Sozialstellen eingereicht werden, bearbeitet der DHV ZH selbst. Anträge, die Hilfesuchende selbst stellen, sind über die zuständige kantonalen Stelle der Winterhilfe Schweiz einzureichen. (Details zur Einweisung sind der Webseite des Deutschen Hilfsvereins Zürich zu entnehmen.)', 'Deutscher Hilfsverein Zürich c/o ESPAS, Naglerwiesenstrasse 4/Postfach, 8049 Zürich,  info@dhv-zh.ch, www.dhv-zh.ch', 'Deutscher Hilfsverein Zürich c/o ESPAS, Naglerwiesenstrasse 4/Postfach, 8049 Zürich, www.', '8049', 'Zürich', '[]', '["info@dhv-zh.ch"]', '["dhv-zh.ch", "www.dhv-zh.ch"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, in CH lebende Bürger mit DE-Nationalität, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Kontoangaben, Kopie Reisepass und letzter Steuererkläung, Kopie Ausländerausweis, Aufstellung Einnahmen/Ausgaben', '{"BEILAGEN": "Kontoangaben, Kopie Reisepass und letzter Steuererkläung, Kopie Ausländerausweis, Aufstellung Einnahmen/Ausgaben", "ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, in CH lebende Bürger mit DE-Nationalität, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (19, 'dora-grob-reinhart-stiftung', 'Dora-Grob-Reinhart-Stiftung', 39, 'Die Stiftung hat den Zweck, aus den Zinsen des Stiftungsvermögens bedürftigen Kindern und armen Frauenpersonen in jeder geeigneten und irgendwie denkbaren Weise Unterstützung zu gewähren, z. B. zur Ermöglichung des Lebensunterhaltes in gesunden und kranken Tagen, Ausrichtung von periodischen oder einmaligen Unterstützungen in bar oder in natura, Ermöglichung von Ferien oder Kuren, Unterbringung in Anstalten, Bezahlung von Arzt- und Verpflegungskosten, Erziehungskosten usw. Anonyme Unterstützungen gewähren wir keine. Wir wollen möglichst viele Details über die zu unterstützende/n Person/en wissen, wie Name, persönliche Daten, Grund für Unterstützung, usw. Wir nehmen keine Privatgesuche an, sondern nur Gesuche, die über anerkannte Institutionen abgeklärt wurden.', 'c/o Paul Reinhart AG, Frau Johanna Reinhart, Technikumstrasse 82, 8400 Winterthur, dgr.stiftung@reinhart.ch', 'c/o Paul Reinhart AG, Frau Johanna Reinhart, Technikumstrasse 82, 8400 Winterthur', '8400', 'Winterthur', '[]', '["dgr.stiftung@reinhart.ch"]', '["reinhart.ch"]', 'Frauen und Kinder in Not', 'Privatpersonen, aber nur über Institutionen angefragt', 'Ganzes Jahr', 'per email an dgr.stiftung@reinhart.ch', 'Kontoangaben', '{"BEILAGEN": "Kontoangaben", "ZIELGRUPPE": "Frauen und Kinder in Not", "EMPFANGSSTELLE": "per email an dgr.stiftung@reinhart.ch", "GESUCHSTELLENDE": "Privatpersonen, aber nur über Institutionen angefragt", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (20, 'dr-arnold-u-huggenberger-stiftung', 'Dr. Arnold U. Huggenberger-Stiftung', 39, 'Unterstützung und Förderung notleidender Kinder bis zum 18. Altersjahr (Unterhalt, Versorgung, Erziehung, Ausbildung) und notleidender Personen ab dem 70. Altersjahr, sofern sie aus den Leistungen von AHV, Altersbeihilfen, Renten oder Pensionen keinen ausreichenden Lebensunterhalt bestreiten können. Die Altersbeschränkungen sind absolut verbindlich.', 'c/o Dr. iur. Peter Herzog, Neuhausstrasse 15, 8044 Zürich, 056 633 63 85, ursi.iten@bluewin.ch', 'c/o Dr. iur. Peter Herzog, Neuhausstrasse 15, 8044 Zürich', '8044', 'Zürich', '["056 633 63 85"]', '["ursi.iten@bluewin.ch"]', '["bluewin.ch"]', 'Kinder/Jugendliche bis zum 18. Altersjahr in finanziell knappen Verhältnissen für Ausbildung, etc., Personen ab 70sten Altersjahr, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Bei Institutionen: Statuten, Mitgliederverzeichnis, Jahresbericht, Jahresrechnung, Budget; bei Privatpersonen: monatliche Einkünfte/Ausgaben, Steuerausweis', '{"BEILAGEN": "Bei Institutionen: Statuten, Mitgliederverzeichnis, Jahresbericht, Jahresrechnung, Budget; bei Privatpersonen: monatliche Einkünfte/Ausgaben, Steuerausweis", "ZIELGRUPPE": "Kinder/Jugendliche bis zum 18. Altersjahr in finanziell knappen Verhältnissen für Ausbildung, etc., Personen ab 70sten Altersjahr, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (21, 'dr-hans-duttweiler-hug-stiftung', 'Dr. Hans Duttweiler-Hug-Stiftung', 40, 'Beiträge an bedürftige Menschen mit Behinderungen Menschen, z. B. für die Anschaffung eines Blindenhundes, Umschulung, technische Hilfsgeräte etc. Höchstbeitrag zurzeit Fr. 500.-- pro Fall, für die gleiche Person nur einmal pro Jahr. Für Bauten und Umbauten dürfen keine Beiträge ausgerichtet werden. Gesuche werden nur von öffentlichen und privaten Fürsorgestellen mit dem offiziellen Formular des kantonalen Amtes für Jugend und Berufsberatung und den üblichen Unterlagen entgegengenommen.', 'c/o Dr. René Schwarzmann, Postfach 163, 8024 Zürich, 044 261 91 00, sts@sts-law.ch', 'c/o Dr. René Schwarzmann, Postfach 163, 8024 Zürich', '8024', 'Zürich', '["044 261 91 00"]', '["sts@sts-law.ch"]', '["sts-law.ch"]', 'Menschen mit Behinderungen', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Menschen mit Behinderungen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (22, 'dr-max-husmann-stiftung', 'Dr. Max Husmann-Stiftung', 40, 'Die Stiftung bezweckt, begabten und der Unterstützung würdigen Jugendlichen eine akademische oder dieser gleichwertigen künstlerische Ausbildung zu ermöglichen oder zu erleichtern.', 'Englischviertelstrasse 58, Postfach 1607, 8032 Zürich, 044 380 61 83, stiftung@maxhusmann.ch, www.maxhusmann.ch', 'Englischviertelstrasse 58, Postfach 1607, 8032 Zürich,, www.', '8032', 'Zürich', '["044 380 61 83"]', '["stiftung@maxhusmann.ch"]', '["maxhusmann.ch", "www.maxhusmann.ch"]', 'Absolventen von einer Erstausbildung an der Universität oder an der ETH bis zum Master-Diplom, Musikhochschulabsolventen ab Lehrdiplom (keine Fachhochschulen)', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kopie Maturitätszeugnis, Lebenslauf, schriftliche Begründung', '{"BEILAGEN": "Ausbildungsbestätigung, Kopie Maturitätszeugnis, Lebenslauf, schriftliche Begründung", "ZIELGRUPPE": "Absolventen von einer Erstausbildung an der Universität oder an der ETH bis zum Master-Diplom, Musikhochschulabsolventen ab Lehrdiplom (keine Fachhochschulen)", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (23, 'dr-stephan-a-porta-stiftung', 'Dr. Stephan à Porta-Stiftung', 40, 'Der Zweck der Stiftung besteht darin, den Ertrag des Stiftungsvermögens wohltätigen und gemeinnützigen Institutionen in der Stadt Zürich oder im Kanton Graubünden zukommen zu lassen. Die Institutionen müssen von den Steuern befreit sein. Kulturelle Zielsetzungen werden nicht unterstützt.', 'Kreuzstrasse 31, 8008 Zürich, 043 222 60 00, info@aporta-stiftung.ch, www.aporta-stiftung.ch', 'Kreuzstrasse 31, 8008 Zürich,, www.', '8008', 'Zürich', '["043 222 60 00"]', '["info@aporta-stiftung.ch"]', '["aporta-stiftung.ch", "www.aporta-stiftung.ch"]', 'Jugend und Familie, Ältere Menschen, Menschen mit Behinderungen, Gesundheit/Krankheit, Migration/Asyl, Armut', 'Institutionen', 'Gesuche können jeweils ausschliesslich von anfangs Dezember bis Ende Februar eingereicht werden.', 'Die Gesuche sind direkt auf der Homepage der Stiftung zu erfassen: aporta-stiftung.ch/gemeinnuetziges-engagement/beitragsgesuche Über Berücksichtigung oder Ablehnung eines Beitragsgesuches entscheidet der Stiftungsrat abschliessend an seiner Juni-Sitzung.', 'Online-Formular: Details zur Institution (Name, Rechtsform, Adresse, Ansprechperson, Tel., E-Mail, Homepage); zum Projekt (Projekttitel, Kurzbegründung Mittelbedarf, Zielgruppe, Anteil Stadtzürcher*innen, Projektdauer/Zeitraum); zu den Kosten; den Beiträgen Dritter
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (24, 'educationsuisse', 'educationsuisse', 41, 'educationsuisse – Ausbildung in der Schweiz berät und unterstützt junge Auslandschweizerinnen und Auslandschweizer, sowie Schüler und Schülerinnen der Schweizerschulen im Ausland, die in der Schweiz eine Ausbildung absolvieren möchten.', 'Ausbildung in der Schweiz, Alpenstrasse 26, 3006 Bern, 031 356 61 04, info@educationsuisse.ch, www.educationsuisse.ch', 'Ausbildung in der Schweiz, Alpenstrasse 26, 3006 Bern,, www.', '3006', 'Bern', '["031 356 61 04"]', '["info@educationsuisse.ch"]', '["educationsuisse.ch", "www.educationsuisse.ch"]', 'Jugend & Familie, Ausbildung, Auslandschweizer/innen (Schweizer Staatsbürger/innen, deren Eltern ihren Wohnsitz im Ausland haben) und Absolventen der Schweizerschulen im Ausland.', 'Privatpersonen', 'Ganzes Jahr. Spezialformular anfordern', 'educationsuisse', 'Ausbildungsbestätigung, Kontoangaben, Liste aller Beilagen auf Anfrage.', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Liste aller Beilagen auf Anfrage.", "ZIELGRUPPE": "Jugend & Familie, Ausbildung, Auslandschweizer/innen (Schweizer Staatsbürger/innen, deren Eltern ihren Wohnsitz im Ausland haben) und Absolventen der Schweizerschulen im Ausland.", "EMPFANGSSTELLE": "educationsuisse", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (25, 'elisabetha-baumann-fonds', 'Elisabetha Baumann-Fonds', 42, 'Zweck der Stiftung ist, Erziehung und Ausbildung unbemittelter, in der Gemeinde Horgen wohnhafter Schweizer Kinder/Jugendlicher durch Zuwendungen aus den Zinserträgen der Stiftung zu unterstützen.', 'c/o Soziales Horgen, Alte Landstrasse 25 Postfach, 8810 Horgen, Tel. 044 728 42 39, soziales@horgen.ch', 'c/o Soziales Horgen, Alte Landstrasse 25 Postfach, 8810 Horgen, Tel.', '8810', 'Horgen', '["044 728 42 39"]', '["soziales@horgen.ch"]', '["horgen.ch"]', 'Jugend & Familie, Ausbildung', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kontoangaben, Angaben über finanzielle Verhältnisse (Vermögen)', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Angaben über finanzielle Verhältnisse (Vermögen)", "ZIELGRUPPE": "Jugend & Familie, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
