INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (27, 'erika-fissmer-stiftung', 'Erika Fissmer-Stiftung', 42, 'Die Stiftung dient ausschliesslich und unmittelbar wohltätigen Zwecken, insbesondere der selbstlosen Unterstützung von Personen, die infolge ihres körperlichen, geistigen oder seelischen Zustands auf die Hilfe anderer angewiesen sind und die wirtschaftliche Not leiden. Hierbei sind Kinder und alte Menschen besonders zu berücksichtigen. Es sind nur Sachspenden zulässig.', 'Via del Sole 43 a, Casella postale 6600, 6600 Locarno, 091 743 45 55', 'Via del Sole 43 a, Casella postale 6600, 6600 Locarno', '6600', 'Locarno', '["091 743 45 55"]', '[]', '[]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Armut', 'Privatpersonen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Armut", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (28, 'ernst-und-frieda-bantli-stiftung', 'Ernst und Frieda Bantli-Stiftung', 43, 'Die Stiftung bezweckt die Leistung von Kostenbeiträgen an hilfsbedürftige, betagte Einwohner/innen der Gemeinde Maur. Die Stiftung kann auch Beiträge an die Errichtung, die Renovation oder die Ausstattung von Bauten in der Gemeinde leisten, die der Unterbringung von Betagten dienen sowie an weitere Bedürfnisse zur Erleichterung des Lebensunterhaltes.', 'Altershilfe Maur, Zürichstrasse 8,8124 Maur, 043 366 13 12', 'Altershilfe Maur, Zürichstrasse 8,8124 Maur', '8124', 'Maur', '["043 366 13 12"]', '[]', '[]', 'Ältere Menschen, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Ältere Menschen, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (29, 'eth-zurich-studienfinanzierung', 'ETH Zürich Studienfinanzierung', 43, 'Subsidiäre Studienbeiträge, Darlehen und Reisekostenbeiträge (im Zusammenhang mit dem ETH-Studium stehend).', 'Rämistrasse 101 · HG F 22.1 · 8092 Zürich ETH-Zentrum · Tel. 044 632 20 88 / 044 632 30 38 · www.ethz.ch > Studium > Finanzielles > Stipendien', 'Rämistrasse 101 · HG F 22.1 · 8092 Zürich ETH-Zentrum · Tel. / · > Studium > Finanzielles > Stipendien', '8092', 'Zürich ETH-Zentrum · Tel. 044 632 20 88 / 044 632 30 38 · www.ethz.ch > Studium > Finanzielles > Stipendien', '["044 632 20 88", "044 632 30 38"]', '[]', '["www.ethz.ch"]', 'Ausschliesslich für Studierende der ETH Zürich (Bachelor- und Masterstudium)', 'Privatpersonen', 'Schweizer Studierende und Niedergelassene mit C-Bewilligung: Sept. - Juni des entsprechenden Studienjahres · Internationale Studierende mit B-Bewilligung: Sept. - Okt. des entsprechenden Studienjahres. Gesuch über eStip einreichen.', 'Studienfinanzierung ETH Zürich', 'einzureichende Beilagen entsprechend speziellem Merkblatt', '{"BEILAGEN": "einzureichende Beilagen entsprechend speziellem Merkblatt", "ZIELGRUPPE": "Ausschliesslich für Studierende der ETH Zürich (Bachelor- und Masterstudium)", "EMPFANGSSTELLE": "Studienfinanzierung ETH Zürich", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Schweizer Studierende und Niedergelassene mit C-Bewilligung: Sept. - Juni des entsprechenden Studienjahres · Internationale Studierende mit B-Bewilligung: Sept. - Okt. des entsprechenden Studienjahres. Gesuch über eStip einreichen."}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (30, 'f-a-kagi-rutishauser-stiftung', 'F. & A. Kägi-Rutishauser-Stiftung', 43, 'Zweck der Stiftung ist, ehrbaren und fähigen, vorzugsweise evangelischen Söhnen und Töchtern schweizerischer Nationalität, vorzugsweise Zürcher Kantonsbürgerinnen/-bürgern, Halb- oder Ganzwaisen, durch finanzielle Unterstützungen und Beiträge eine angemessene Berufslehre zu ermöglichen. Studiumsstipendien sind ausgeschlossen.
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (31, 'fondation-oertli-stiftung', 'Fondation  Oertli-Stiftung', 44, 'Unterstützung privater und öffentlicher, kultureller und gemeinnütziger Projekte, die das Verständnis und den Austausch zwischen den Sprachregionen der Schweiz fördern. Der Oertli-Preis geht an Persönlichkeiten, die sich um die Kontakte zwischen den Landesteilen bemüht haben.', 'Seestrasse 279, 8038 Zürich, 044 481 53 85, oertlistiftung@bluewin.ch, www.oertlistiftung.ch', 'Seestrasse 279, 8038 Zürich', '8038', 'Zürich', '["044 481 53 85"]', '["oertlistiftung@bluewin.ch"]', '["bluewin.ch", "www.oertlistiftung.ch"]', 'öffentliche und private, kulturelle und gemeinnützige Institutionen', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Unterlagen mit entsprechendem Budget und Begleitbrief können jederzeit eingereicht werden.', NULL, NULL, '{"ZIELGRUPPE": "öffentliche und private, kulturelle und gemeinnützige Institutionen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Unterlagen mit entsprechendem Budget und Begleitbrief können jederzeit eingereicht werden."}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (32, 'fred-tschanz-stiftung', 'Fred Tschanz-Stiftung', 44, 'Die Stiftung richtet Bar- oder Naturalspenden an bedürftige, geistig und/oder körperlich Menschen mit Behinderungen Schweizer Kinder und Jugendliche mit Wohnsitz in der Region Zürich für Schulung und Weiterbildung, medizinische Leistungen und Pflege sowie Betreuung.', 'Limmatquai 2, Postfach, 8024 Zürich, 044 267 47 60', 'Limmatquai 2, Postfach, 8024 Zürich', '8024', 'Zürich', '["044 267 47 60"]', '[]', '[]', 'Jugend & Familie, Menschen mit Behinderungen, Ausbildung', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Arztzeugnis, Ausbildungsbestätigung, Referenzen', '{"BEILAGEN": "Arztzeugnis, Ausbildungsbestätigung, Referenzen", "ZIELGRUPPE": "Jugend & Familie, Menschen mit Behinderungen, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (33, 'frieda-locher-hofmann-stiftung', 'Frieda  Locher-Hofmann-Stiftung', 44, 'Unterstützung gemeinnützig tätiger Institutionen und Hilfswerke aller Art mit Sitz und verantwortlicher Leitung in der Schweiz; insbesondere auch die Unterstützung medizinischer Forschung, medizinischer Heilstätten, der Fürsorge für das Alter und körperlich oder geistig Invalider.', 'c/o adtrexa AG, Gessnerallee 28, 8001 Zürich', 'c/o adtrexa AG, Gessnerallee 28, 8001 Zürich', '8001', 'Zürich', '[]', '[]', '[]', 'Menschen mit Behinderungen, Kranke, Soz. Institutionen, Gesundheit', 'Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Menschen mit Behinderungen, Kranke, Soz. Institutionen, Gesundheit", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (97, 'pro-senectute-kanton-zurich', 'Pro Senectute Kanton Zürich', 67, 'Fachorganisation für Altersfragen, Bearbeitung von Altersfragen, Grundlagen- und Entwicklungsarbeit, Träger verschiedener Dienste auf kantonaler, regionaler und kommunaler Ebene. Angebote kantonal:
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (34, 'friedrich-und-amalie-meyer-baumann-stiftung', 'Friedrich und Amalie Meyer-Baumann-Stiftung', 45, 'Aus den Erträgen des Stiftungsvermögens sollen bedürftigen blinden Menschen zum Besuche von Schulen, zur Erlernung eines Berufes, zur beruflichen Weiterbildung oder Umschulung in der beruflichen Tätigkeit Beiträge ausgerichtet werden. Beiträge können auch für ärztliche Heilung (inkl. Operationen) zur Behebung der Blindheit und zur körperlichen Ertüchtigung gewährt werden. Die Ausrichtung von Beiträgen kann auch an Heime, Schulen und sonstige Institutionen, die den vorerwähnten Zwecken dienen, erfolgen. Beitragsempfänger müssen ihren Wohnsitz in den Kantonen Zürich oder Schaffhausen haben. Ebenso muss der Sitz eines Heimes, einer Schule usw. im Kanton Zürich oder Schaffhausen liegen oder es muss ein zu unterstützender Bewohner eines Heimes oder der Besucher einer Schule usw. aus einem der beiden Kantone stammen.', 'c/o Armin Kuhn, Zwischenweg 28 a, 8413 Neftenbach, 044 752 37 30 (Geschäft), 052 315 42 62 (Privat), armin.cornelia.kuhn@bluewin.ch', 'c/o Armin Kuhn, Zwischenweg 28 a, 8413 Neftenbach, (Geschäft), (Privat)', '8413', 'Neftenbach', '["044 752 37 30", "052 315 42 62"]', '["armin.cornelia.kuhn@bluewin.ch"]', '["bluewin.ch"]', 'Blinde und SehMenschen mit Behinderungen, Ausbildung', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Arztzeugnis, Kontoangaben', '{"BEILAGEN": "Arztzeugnis, Kontoangaben", "ZIELGRUPPE": "Blinde und SehMenschen mit Behinderungen, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (35, 'fritz-gerber-stiftung-fur-begabte-junge-menschen', 'Fritz-Gerber-Stiftung für begabte junge Menschen', 45, 'Die Stiftung bezweckt auf ausschliesslich gemeinnütziger Basis die Förderung begabter junger Menschen im Alter zwischen 10 und 25 Jahren, mit dauerhaftem Wohnsitz in der Schweiz durch Leistung finanzieller Beiträge zur Aus-, Fort- und Weiterbildung (u. a. Sport, Handwerk). Sie ist tätig, wo zur Erreichung des Stiftungszwecks keine öffentlichen Gelder zur Verfügung stehen.', 'Stampfenbachstrasse 125, 8006 Zürich, 044 260 53 83, info@fritz-gerber-stiftung.ch, www.fritz-gerber-stiftung.ch', 'Stampfenbachstrasse 125, 8006 Zürich,, www.', '8006', 'Zürich', '["044 260 53 83"]', '["info@fritz-gerber-stiftung.ch"]', '["fritz-gerber-stiftung.ch", "www.fritz-gerber-stiftung.ch"]', 'Unterstützungsberechtigt sind junge Menschen im Alter zwischen 10 und 25 Jahren, die in der Schweiz ihren dauernden Wohnsitz (mindestens die vergangenen drei Jahre) haben. Unterstützt werden Gesuche begabter junger Menschen in den Bereichen Schule (inkl. Fachhochschulen), Handwerk, Kultur und Sport. Nicht berücksichtigt werden Gesuche von Bewerbern der Universitäten und der ETH.', 'Privatpersonen', 'Ganzes Jahr', 'Schriftliches Gesuch an die Geschäftsstelle oder digital via Website hochladen', 'Ausbildungsbestätigung, Kontoangaben, Referenzen, Lebenslauf, Kostenaufstellung, Steuerformulare', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen, Lebenslauf, Kostenaufstellung, Steuerformulare", "ZIELGRUPPE": "Unterstützungsberechtigt sind junge Menschen im Alter zwischen 10 und 25 Jahren, die in der Schweiz ihren dauernden Wohnsitz (mindestens die vergangenen drei Jahre) haben. Unterstützt werden Gesuche begabter junger Menschen in den Bereichen Schule (inkl. Fachhochschulen), Handwerk, Kultur und Sport. Nicht berücksichtigt werden Gesuche von Bewerbern der Universitäten und der ETH.", "EMPFANGSSTELLE": "Schriftliches Gesuch an die Geschäftsstelle oder digital via Website hochladen", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (36, 'fur-die-kinder-fur-die-zukunft', 'Für die Kinder – Für die Zukunft', 46, 'Für die Kinder - Für die Zukunft Winterthur - Andelfingen will die Lage von fremdbetreuten Kindern verbessern und hilft mit, Kindern Ihre Familien zu erhalten. Hilfe und finanzielle Unterstützung für Pflegekinder und Eltern, alleinerziehende Mütter und Väter.', 'Winterthur-Andelfingen, Untere Briggerstrasse 59, 8406 Winterthur, 052 203 02 72, kinder-zukunft@bluewin.ch, www.kinder-zukunft.ch', 'Winterthur-Andelfingen, Untere Briggerstrasse 59, 8406 Winterthur', '8406', 'Winterthur', '["052 203 02 72"]', '["kinder-zukunft@bluewin.ch"]', '["bluewin.ch", "www.kinder-zukunft.ch"]', 'Jugend & Familie', 'Privatpersonen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
