INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (41, 'gemeinnutzige-gesellschaft-des-bezirks-bulach', 'Gemeinnützige Gesellschaft des Bezirks Bülach', 47, 'Beiträge an Jugendliche und bedrängte Familien im Bezirk Bülach. Anträge in der Regel über soziale Institutionen.', 'c/o Kurt Schreiber, Hasenrain 8, 8305 Dietlikon, 044 833 08 35, praesident@ggbuelach.ch, www.ggbuelach.ch', 'c/o Kurt Schreiber, Hasenrain 8, 8305 Dietlikon,, www.', '8305', 'Dietlikon', '["044 833 08 35"]', '["praesident@ggbuelach.ch"]', '["ggbuelach.ch", "www.ggbuelach.ch"]', 'Jugend & Familie, Menschen mit Behinderungen, Aus- und Weiterbildung in Notfällen, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kontoangaben, Finanzielle Übersicht, Begleitschreiben einer sozialen Institution', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Finanzielle Übersicht, Begleitschreiben einer sozialen Institution", "ZIELGRUPPE": "Jugend & Familie, Menschen mit Behinderungen, Aus- und Weiterbildung in Notfällen, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (42, 'gemeinnutzige-gesellschaft-des-bezirks-dielsdorf', 'Gemeinnützige Gesellschaft des Bezirks Dielsdorf', 47, 'Finanzielle Unterstützung von Einzelpersonen, Jugendlichen, Fürsorgeinstitutionen und Kulturträgern im Bezirk Dielsdorf. Unentgeltliche Rechtsauskunft jeden ersten Mittwoch des Monats ab 18.00 Uhr im Werkgebäude an der Industriestrasse 20 in 8155 Niederhasli. 10% Ermässigung für Einwohner des Bezirks Dielsdorf auf Übernachtungen im Hotel Bellevue in Davos-Wiesen GR.', 'c/o Regula Müller, Wehntalerstrasse 54, 8162 Sünikon, 079 209 47 67 (Natel Präsident), praesi@ggbd.ch, www.ggbd.ch', 'c/o Regula Müller, Wehntalerstrasse 54, 8162 Sünikon, (Natel Präsident), www.', '8162', 'Sünikon', '["079 209 47 67"]', '["praesi@ggbd.ch"]', '["ggbd.ch", "www.ggbd.ch"]', 'Jugend, Familie, Betagte, Soz. Institutionen, Armut, Verschiedenes', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'sehr einfach mit schriftlichem Gesuch inkl. Kurzbegründung', '{"BEILAGEN": "sehr einfach mit schriftlichem Gesuch inkl. Kurzbegründung", "ZIELGRUPPE": "Jugend, Familie, Betagte, Soz. Institutionen, Armut, Verschiedenes", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
