INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (44, 'gemeinnutzige-gesellschaft-des-bezirks-meilen', 'Gemeinnützige Gesellschaft des Bezirks Meilen', 48, 'Beiträge für Kinder, Jugendliche, Erwachsene und Familien (im Raum des Bezirks Meilen) in finanziellen Notlagen. Wiederholte Beiträge eher als Ausnahme. Beiträge an Ferien und Kuren von erholungsbedürftigen Personen, eventuell an die Kosten einer Haushaltshilfe während der Abwesenheit der Mutter. Vermittlung von Ferien an Leute in beengter Lage. Die Gemeinnützige Gesellschaft ist dafür da, Härtefälle zu lindern, denen das öffentliche Fürsorgewesen nicht gerecht werden kann.', 'Philipp Huser, Präsident, Postfach 802, 8708 Männedorf, 044 928 15 25 (Büro), info@ggmeilen.ch, www.ggmeilen.ch', 'Philipp Huser, Präsident, Postfach 802, 8708 Männedorf, (Büro), www.', '8708', 'Männedorf', '["044 928 15 25"]', '["info@ggmeilen.ch"]', '["ggmeilen.ch", "www.ggmeilen.ch"]', NULL, 'Privatpersonen', NULL, NULL, NULL, '{"GESUCHSTELLENDE": "Privatpersonen"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (45, 'gemeinnutzige-gesellschaft-des-bezirks-pfaffikon', 'Gemeinnützige Gesellschaft des Bezirks Pfäffikon', 48, 'Die GGBP unterstützt Einzelpersonen und Familien des Bezirks Pfäffikon in Notsituationen. Sie kann   Ausbildungsbeiträge an Jugendliche und Erwachsene gewähren, die keinen Anspruch auf staatliche Stipendien haben. Die Bezirksgesellschaft unterstützt gemeinnützige kulturelle, sportliche und soziale Anlässe und Aktivitäten von überkommunaler, die Ortssektionen solche von kommunaler Bedeutung. Die Bibliotheken in den Gemeinden erhalten Förderbeiträge. Die Freiwilligenarbeit wird gefördert. Die GGBP ist offen für neue Projekte und Aufgaben, mit denen das Zusammenleben und das Gemeinwohl im Bezirk Pfäffikon gefördert und unterstützt werden kann.', 'Gemeinnützige Gesellschaft des Bezirkes Pfäffikon, Postfach 18, 8332 Russikon, info@ggbp.ch', 'Gemeinnützige Gesellschaft des Bezirkes Pfäffikon, Postfach 18, 8332 Russikon', '8332', 'Russikon', '[]', '["info@ggbp.ch"]', '["ggbp.ch"]', 'Jugend und Familie, Ältere Menschen, Armut, Ausbildung, Freiwilligenarbeit, zusätzlich zu bereits vorhandenen ältere Menschen', 'Privatpersonen, Institutionen', 'Ganzes Jahr jederzeit', 'Gemeinnützige gesellschaft des Bezirkes Pfäffikon, Margrit Manser, Präsidentin, Kratzgasse 4, 8307 Ottikon bei Kemptthal', 'Privatpersonen: nur via soziale Institution /
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (46, 'gemeinnutzige-gesellschaft-des-bezirks-uster', 'Gemeinnützige Gesellschaft des Bezirks Uster', 49, 'Gewährung subsidiärer Hilfe an Einzelpersonen und Familien zur Überbrückung schwieriger Lebenslagen. Unterstützung der Aus- und Weiterbildung. Bedingung: gesetzlicher Wohnsitz im Bezirk Uster.', 'Jürg Neff, Amtsstrasse 1, 8610 Uster, 044 222 12 45, juerg.neff@neffconcept.com', 'Jürg Neff, Amtsstrasse 1, 8610 Uster', '8610', 'Uster', '["044 222 12 45"]', '["juerg.neff@neffconcept.com"]', '["neffconcept.com"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen, Ausbildung, Armut', 'Privatpersonen', 'Ganzes Jahr', 'Schriftliches Gesuch', 'Ausbildungsbestätigung, Kontoangaben, Referenzen, Begründung des Gesuchs, Lebenslauf', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen, Begründung des Gesuchs, Lebenslauf", "ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen, Ausbildung, Armut", "EMPFANGSSTELLE": "Schriftliches Gesuch", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
