INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (48, 'georg-und-bertha-schwyzer-winiker-stiftung', 'Georg und Bertha Schwyzer- Winiker-Stiftung', 50, 'Leistung von Beiträgen an den Lebensunterhalt, Pflegekosten und Kur- und Ferienaufenthalte, sowie an Therapien und Hilfsmittel für Kinder und Jugendliche in der Schweiz, unabhängig von Religion und Nationalität, die geistig oder körperlich behindert sind, an einer lebensbedrohenden Krankheit leiden oder Opfer einer sexuellen oder körperlichen Misshandlung geworden sind.', 'Sekretariat M. Schwyzer, Parkring 51, 8002 Zürich, 079 373 06 03, schwyzer.stiftung@bluewin.ch', 'Sekretariat M. Schwyzer, Parkring 51, 8002 Zürich', '8002', 'Zürich', '["079 373 06 03"]', '["schwyzer.stiftung@bluewin.ch"]', '["bluewin.ch"]', 'Jugend, Familie, Menschen mit Behinderungen, Kranke, Ausländer/innen, Gesundheit, Armut', 'Privatpersonen', 'Ganzes Jahr. Der Stiftungsrat tagt nur im Mai und November jedes Jahres', NULL, 'Arztzeugnis', '{"BEILAGEN": "Arztzeugnis", "ZIELGRUPPE": "Jugend, Familie, Menschen mit Behinderungen, Kranke, Ausländer/innen, Gesundheit, Armut", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Der Stiftungsrat tagt nur im Mai und November jedes Jahres"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (49, 'gertrude-von-meissner-stiftung', 'Gertrude von Meissner-Stiftung', 50, NULL, NULL, NULL, NULL, NULL, '[]', '[]', '[]', NULL, NULL, NULL, NULL, NULL, '{}', 'overview_row_only', 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (50, 'geschwister-mader-stiftung', 'Geschwister  Mäder-Stiftung', 50, 'Die Stiftung bezweckt die finanzielle Unterstützung der katholischen Studentenseelsorge an den zürcherischen Hochschulen bzw. die Förderung der Aktivitäten des katholischen Akademikerhauses in Zürich, ausnahmsweise die Unterstützung anderweitiger Seelsorgeanliegen der katholischen Kirche.', 'c/o Dr. Albert Gnägi, Zollikerstrasse 60, 8702 Zollikon', 'c/o Dr. Albert Gnägi, Zollikerstrasse 60, 8702 Zollikon', '8702', 'Zollikon', '[]', '[]', '[]', NULL, 'Institutionen', NULL, NULL, NULL, '{"GESUCHSTELLENDE": "Institutionen"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (51, 'gottfried-r-friedli-stiftung', 'Gottfried R. Friedli-Stiftung', 51, 'Die Stiftung bezweckt die Förderung der akademischen Ausbildung. Dem Stifterwillen entsprechend sollen junge, im Bezirk Bülach wohnhafte oder dort heimatberechtigte Leute in der akademischen Laufbahn gefördert und unterstützt werden. Auch Mittelschüler können unterstützt werden, wenn dadurch das Studium ermöglicht werden kann; ebenso können gut ausgewiesene Akademiker nach Abschluss des Studiums unterstützt werden.', 'c/o Kantonsschule Zürcher Unterland, Kantonsschulstrasse 23, 8180 Bülach, 044 872 31 31, jakob.hauser@kzu.ch', 'c/o Kantonsschule Zürcher Unterland, Kantonsschulstrasse 23, 8180 Bülach', '8180', 'Bülach', '["044 872 31 31"]', '["jakob.hauser@kzu.ch"]', '["kzu.ch"]', 'Jugend & Familie, Ausbildung', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kontoangaben, Referenzen, Studienplan, Budgetplan', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen, Studienplan, Budgetplan", "ZIELGRUPPE": "Jugend & Familie, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (52, 'gottfried-scharer-stiftung', 'Gottfried Schärer Stiftung', 51, 'Die Gottfried Schärer-Stiftung hat den Zweck, in den Kantonen Zürich und Thurgau zugunsten der bäuerlichen Bevölkerung der Gemeinnützigkeit zu dienen und deren Bestrebungen zu fördern und zu unterstützen. In erster Linie werden betagtes oder invalides bäuerliches Dienstpersonal beiderlei Geschlechts, aber auch betagte und bedürftige Kleinbauern und deren Familien unterstützt. Subsidiär können auch Landwirten, die Klein- und Mittelbetriebe bewirtschaften, Unterstützungen zum Zwecke der Existenzsicherung in geeigneter Form gewährt werden.', 'c/o aurora treuhand ag, Seestrasse 149, 8700 Küsnacht ZH, 044 492 41 92, aurora.ag@bluewin.ch', 'c/o aurora treuhand ag, Seestrasse 149, 8700 Küsnacht ZH', '8700', 'Küsnacht ZH', '["044 492 41 92"]', '["aurora.ag@bluewin.ch"]', '["bluewin.ch"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausbildung, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Kontoangaben', '{"BEILAGEN": "Kontoangaben", "ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausbildung, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (53, 'grutli-stiftung-zurich', 'Grütli Stiftung Zürich', 51, 'Die Grütli Stiftung Zürich wurde 1981 gegründet. Zweck der Stiftung sind Zuwendungen an gemeinnützige, kulturelle und wohltätige Institutionen in der Region Zürich (keine Einzelfallhilfe!).', 'Stampfenbachstrasse 125, 8006 Zürich, 044 254 60 31, info@gruetli-stiftung.ch, www.gruetli-stiftung.ch', 'Stampfenbachstrasse 125, 8006 Zürich,, www.', '8006', 'Zürich', '["044 254 60 31"]', '["info@gruetli-stiftung.ch"]', '["gruetli-stiftung.ch", "www.gruetli-stiftung.ch"]', 'Jugend und Familie, Ältere Menschen, Menschen mit Behinderungen, Gesundheit/Krankheit, Migration/Asyl, Armut, Ausbildung', 'Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend und Familie, Ältere Menschen, Menschen mit Behinderungen, Gesundheit/Krankheit, Migration/Asyl, Armut, Ausbildung", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (54, 'hans-henny-fonds-der-albertus-magnus-stiftung', 'Hans Henny Fonds der Albertus Magnus Stiftung', 52, 'Das Fondsvermögen soll im Sinne des Stiftungszweckes für die Förderung und Unterstützung religiöser und kirchlicher Bestrebungen der römisch-katholischen Bevölkerung des ganzen Kantons Zürich verwendet werden, insbesondere auch für die Ausbildung der katholischen Jugend. Der Fonds gewährt keine Beiträge an Individualpersonen.', 'Thomas Niedermann Consulting, Limmatquai 102, 8001 Zürich, 043 960 32 90, Th.Niedermann@bluewin.ch', 'Thomas Niedermann Consulting, Limmatquai 102, 8001 Zürich', '8001', 'Zürich', '["043 960 32 90"]', '["Th.Niedermann@bluewin.ch"]', '["bluewin.ch"]', 'Jugend & Familie, Ausblidung, Armut', 'Institutionen', NULL, NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie, Ausblidung, Armut", "GESUCHSTELLENDE": "Institutionen"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (55, 'hans-jegen-stiftung', 'Hans Jegen Stiftung', 52, 'Ausrichtung von Leistungen an Kinder und Jugendliche in der Schweiz, die in irgendeiner Weise beeinträchtigt sind. Unterstützung von Heimen und Hilfswerken für die Pflege und die Betreuung von Kindern und Jugendlichen mit Behinderung.', 'Oerlikonerstrasse 38, 8057 Zürich, 044 312 43 40, stiftung@jegen-immobilien.ch', 'Oerlikonerstrasse 38, 8057 Zürich', '8057', 'Zürich', '["044 312 43 40"]', '["stiftung@jegen-immobilien.ch"]', '["jegen-immobilien.ch"]', 'Behinderte Kinder und Jugendliche in der Schweiz mit Fokus Südostschweiz.', 'Privatpersonen, Institutionen', 'Februar und Oktober', NULL, NULL, '{"ZIELGRUPPE": "Behinderte Kinder und Jugendliche in der Schweiz mit Fokus Südostschweiz.", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Februar und Oktober"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (56, 'hans-konrad-rahn-stiftung', 'Hans Konrad Rahn-Stiftung', 52, 'Die Stiftung bezweckt auf ausschliesslich gemeinnütziger Basis die Unterstützung sozialer Institutionen und Projekte zugunsten benachteiligter Menschen in der Schweiz, vorab in der Region Zürich. Sie kann auch kulturelle und wissenschaftliche Institutionen in der Region Zürich und in der Schweiz unterstützen. Die Stiftung spricht auf der Basis von schriftlichen Gesuchen - ergänzt durch eigene Abklärungen - Beiträge, deren Höhe individuell ist. Diese Gelder sind von den Begünstigten zielgerichtet einzusetzen.', 'Kirchgasse 38, Postfach 373, 8024 Zürich, 044 254 60 33, info@hanskonradrahn-stiftung.ch, www.rahn-group.com', 'Kirchgasse 38, Postfach 373, 8024 Zürich', '8024', 'Zürich', '["044 254 60 33"]', '["info@hanskonradrahn-stiftung.ch"]', '["hanskonradrahn-stiftung.ch", "www.rahn-group.com"]', 'Soziale Institutionen', 'Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Soziale Institutionen", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (57, 'hans-trachsler-fonds', 'Hans Trachsler-Fonds', 52, 'Der Hans Trachsler-Fonds wird für "guttätige Zwecke" in der Stadt Wetzikon verwendet, nach sorgfältiger Prüfung und Gutdünken der Fonds-Kommission. Es werden vorwiegend Gesuche für Projekte von gemeinnützigen Vereinen im Jugend, Alters- und Sozialbereich unterstützt. Gesuche für Einzelpersonen werden nur ausnahmsweise bewilligt; sollte ein solches Gesuch einer Einzelperson bewilligt werden, wird immer eine Eigenleistung vom Gesuchsteller erwartet.', 'c/o Bereich Finanzen Wetzikon, Bahnhofstrasse 167, 8620 Wetzikon ZH, 044 931 32 35, finanzen@wetzikon.ch, www.wetzikon.ch  Verwaltung  Finanzen  Hans Trachsler-Fonds', 'c/o Bereich Finanzen Wetzikon, Bahnhofstrasse 167, 8620 Wetzikon ZH,, www. Verwaltung Finanzen Hans Trachsler-Fonds', '8620', 'Wetzikon ZH', '["044 931 32 35"]', '["finanzen@wetzikon.ch"]', '["wetzikon.ch", "www.wetzikon.ch"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (58, 'hans-und-mathilde-eichenberger-stiftung', 'Hans und Mathilde Eichenberger-Stiftung', 53, 'Hilfeleistungen an minderbemittelte Familien, die ihren Wohnsitz in Affoltern am Albis haben. Unterstützung von in Not geratenem Pflegepersonal, das in Affoltern am Albis arbeitet und wohnhaft ist.', 'c/o Furrer Treuhand, Lindenmoosstrasse 4, 8910 Affoltern am Albis', 'c/o Furrer Treuhand, Lindenmoosstrasse 4, 8910 Affoltern am Albis', '8910', 'Affoltern am Albis', '[]', '[]', '[]', 'Jugend & Familie, Ausbildung, Armut', 'Privatpersonen', 'März und Oktober. Spezialformular anfordern', NULL, 'Kontoangaben, Budget, Steuerzahlen', '{"BEILAGEN": "Kontoangaben, Budget, Steuerzahlen", "ZIELGRUPPE": "Jugend & Familie, Ausbildung, Armut", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "März und Oktober. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (59, 'hans-vogel-stiftung', 'Hans Vogel-Stiftung', 53, 'Unterstützung gebrechlicher Kinder und Institutionen, die gebrechliche Kinder betreuen. Die beschränkten Mittel werden prioritär im Raum Winterthur vergeben.', 'c/o Zürcher Kantonalbank, WFES Stiftungen, Postfach, 8010 Zürich', 'c/o Zürcher Kantonalbank, WFES Stiftungen, Postfach, 8010 Zürich', '8010', 'Zürich', '[]', '[]', '[]', 'Menschen mit Behinderungen', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Menschen mit Behinderungen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (60, 'hans-wegmann-stiftung', 'Hans Wegmann-Stiftung', 53, 'Gewährung von finanziellen Beiträgen für zusätzliche integrative Förderung von Schülerinnen und Schülern in Schulklassen der Stadt Zürich oder im Rahmen der Ausbildung bis zum 20. Altersjahr. Die Bedingungen für den Bezug von Hilfeleistungen richten sich nach der "Verordnung über die sonderpädagogischen Massnahmen" des Kantons Zürich vom 11.07.2007, resp. nach dem übergeordneten kantonalen Volksschulgesetz vom 07.02.2005.', 'Usteristrasse 17, 8001 Zürich, 043 497 33 11, wegmannstiftung@bluewin.ch', 'Usteristrasse 17, 8001 Zürich', '8001', 'Zürich', '["043 497 33 11"]', '["wegmannstiftung@bluewin.ch"]', '["bluewin.ch"]', 'Schülerinnen und Schüler in Volksschulklassen der Stadt Zürich sowie Lernende mit Wohnsitz in der Stadt Zürich.', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', 'Hans Wegmann-Stiftung, Usteristrasse 17, 8001 Zürich', 'Ausbildungsbestätigung. Es muss ein sonderpädagogisches Bedürfnis vorhanden sein, welches durch die Schulleitung zu bestätigen ist. Der Anmeldung ist die Protokollkopie des schulischen Standortgespräches beizulegen.', '{"BEILAGEN": "Ausbildungsbestätigung. Es muss ein sonderpädagogisches Bedürfnis vorhanden sein, welches durch die Schulleitung zu bestätigen ist. Der Anmeldung ist die Protokollkopie des schulischen Standortgespräches beizulegen.", "ZIELGRUPPE": "Schülerinnen und Schüler in Volksschulklassen der Stadt Zürich sowie Lernende mit Wohnsitz in der Stadt Zürich.", "EMPFANGSSTELLE": "Hans Wegmann-Stiftung, Usteristrasse 17, 8001 Zürich", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
