INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (64, 'helfer-und-schluter-stiftung', 'Helfer und Schlüter-Stiftung', 55, 'Zuwendungen an Unterhalt/Pflege bedürftiger kranker Personen, insbesondere für Multiple-Sklerose-Patientinnen und -Patienten, Querschnittgelähmte und Patientinnen/Patienten mit ähnlichen Krankheiten.', 'p. A. Notar Franziska Iseli, Bahnhofplatz 3, 3011 Bern, 031 310 25 50, kanzlei@notariatiseli.ch', 'p. A. Notar Franziska Iseli, Bahnhofplatz 3, 3011 Bern', '3011', 'Bern', '["031 310 25 50"]', '["kanzlei@notariatiseli.ch"]', '["notariatiseli.ch"]', 'Menschen mit Behinderungen, Kranke', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Finanzierungsplan, Monatsbudget', '{"BEILAGEN": "Finanzierungsplan, Monatsbudget", "ZIELGRUPPE": "Menschen mit Behinderungen, Kranke", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
