INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (66, 'huber-graf-und-billeter-graf-stiftung', 'Huber-Graf und Billeter-Graf-Stiftung', 56, 'Hilfe nur für bedürftige Einzelpersonen, nicht für Institutionen. Fürsorge für blinde, taubstumme, Menschen mit Behinderungen und gebrechliche Personen sowie sonst Bedürftige. Wohnsitz oder Bürgerrecht: Kanton Zürich (vorwiegend). Auszahlung: à fonds perdu. Wiederholte Zahlungen nur ausnahmsweise. Allgemeines Formular, Gesuche sind nicht von privaten Bedürftigen selbst, sondern über eine antragstellende Institution  einzusenden (z. B. Caritas, Jugendsekretariate, Sozialberatungsstellen usw.).', 'c/o Stiffler & Partner, Dufourstrasse 101, 8008 Zürich, 044 388 48 48, dieter.gessler@stplaw.ch', 'c/o Stiffler & Partner, Dufourstrasse 101, 8008 Zürich', '8008', 'Zürich', '["044 388 48 48"]', '["dieter.gessler@stplaw.ch"]', '["stplaw.ch"]', 'Betagte, Menschen mit Behinderungen, Kranke, Übrige, Ausländer/innen, Gesundheit, Armut, Verschiedenes', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Arztzeugnis, Kontoangaben, Angaben zur Einkommenssituation, Vermögen und Schulden, Gesuche an andere Institutionen, Begründung des Gesuches mit erforderlichem Betrag, ev. Finanzierungsplan, Einzahlungsschein', '{"BEILAGEN": "Arztzeugnis, Kontoangaben, Angaben zur Einkommenssituation, Vermögen und Schulden, Gesuche an andere Institutionen, Begründung des Gesuches mit erforderlichem Betrag, ev. Finanzierungsplan, Einzahlungsschein", "ZIELGRUPPE": "Betagte, Menschen mit Behinderungen, Kranke, Übrige, Ausländer/innen, Gesundheit, Armut, Verschiedenes", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (67, 'hulfsgesellschaft-in-zurich', 'Hülfsgesellschaft in Zürich', 56, 'Gewährung von Unterstützungen (bis max. CHF 2''000.-) an Einzelpersonen jeden Alters und Zivilstandes, die in eine Notlage geraten sind. Wohnsitz: Kanton Zürich (ohne Bezirk Winterthur). Gesuche werden nur von öffentlichen und privaten Fürsorgestellen und Fürsorgeorganisationen entgegengenommen. Das Gesuchsformular kann unter www. hülfsgesellschaft-zürich.ch heruntergeladen werden. QR-Einzahlungsschein beilegen!', 'Hülfsgesellschaft in Zürich, Unterstützungskommission, Kirchgasse 27, 8001 Zürich, +41 44 361 96 23, gesuche@huege.ch, www.hülfsgesellschaft-zürich.ch', 'Hülfsgesellschaft in Zürich, Unterstützungskommission, Kirchgasse 27, 8001 Zürich, +41 44 361 96 23', '8001', 'Zürich', '[]', '["gesuche@huege.ch"]', '["huege.ch", "www.hülfsgesellschaft-zürich.ch"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Gesundheit/Krankheit, Ausländer/innen, Ausbildung, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Sitzungstermine und Einsendeschluss sind auf unserer Homepage ersichtlich.', 'Gesuche in schriftlicher Form ausschliesslich per Post an: Hülfsgesellschaft in Zürich, Unterstützungskommission, Kirchgasse 27, 8001 Zürich', 'Ausbildungsbestätigung, Kontoangaben, Formular «Beitragsgesuch an Fonds und Stiftungen» (www.hülfsgesellsellschaft-zürich.ch)', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Formular «Beitragsgesuch an Fonds und Stiftungen» (www.hülfsgesellsellschaft-zürich.ch)", "ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Gesundheit/Krankheit, Ausländer/innen, Ausbildung, Armut", "EMPFANGSSTELLE": "Gesuche in schriftlicher Form ausschliesslich per Post an: Hülfsgesellschaft in Zürich, Unterstützungskommission, Kirchgasse 27, 8001 Zürich", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Sitzungstermine und Einsendeschluss sind auf unserer Homepage ersichtlich."}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (68, 'ilse-und-ernst-braunschweig-stiftung', 'Ilse und Ernst Braunschweig Stiftung', 57, 'Ausübung von Wohltätigkeit sowie Unterstützung von steuerbefreiten Institutionen, die sich öffentlichen, kulturellen, Erziehungs-, Unterrichts- und Kultus-Zwecken widmen oder die der Fürsorge für Arme und Kranke, für Alter und Invalidität dienen', 'Dr. Arthur Braunschweig, Im Stieg 7, 8134 Adliswil, arthur@braunschweig.ch', 'Dr. Arthur Braunschweig, Im Stieg 7, 8134 Adliswil', '8134', 'Adliswil', '[]', '["arthur@braunschweig.ch"]', '["braunschweig.ch"]', 'Die Ilse und Ernst Braunschweig-Stiftung unterstützt unterschiedliche Projekte, i.d.R. über einige Jahre. Neue Projekte werden u.a. daraufhin geprüft, ob die Projektverantwortlichen selbst engagiert sind und ob der Stiftungsrat die Projektverantwortlichen ohne grossen Zusatzaufwand selbst beurteilen kann.', 'Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Die Ilse und Ernst Braunschweig-Stiftung unterstützt unterschiedliche Projekte, i.d.R. über einige Jahre. Neue Projekte werden u.a. daraufhin geprüft, ob die Projektverantwortlichen selbst engagiert sind und ob der Stiftungsrat die Projektverantwortlichen ohne grossen Zusatzaufwand selbst beurteilen kann.", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (69, 'jacobs-foundation', 'Jacobs Foundation', 57, 'Ziel der Jacobs Foundation ist es, das Potenzial junger Menschen zu erschliessen und ihnen dabei zu helfen, zu sozial verantwortungsbewussten und produktiven Mitgliedern der Gesellschaft zu werden. Die Stiftung finanziert Forschung auf dem Gebiet der positiven Jugendentwicklung sowie konkrete Interventionsprojekte.Die Jacobs Foundation zieht unangeforderte Anträge und spontane Projektvorschläge in aller Regel nicht in Betracht. Projekte werden in enger Zusammenarbeit mit  existierenden Partnern oder mit Partnern, die von der Stiftung ausgewählt werden, entwickelt.', 'Seefeldquai 17, Postfach, 8034 Zürich, 044 388 61 23, jf@jacobsfoundation.org, www.jacobsfoundation.org', 'Seefeldquai 17, Postfach, 8034 Zürich,, www.', '8034', 'Zürich', '["044 388 61 23"]', '["jf@jacobsfoundation.org"]', '["jacobsfoundation.org", "www.jacobsfoundation.org"]', 'Jugend & Familie, Wissenschaftler, Nachwuchs- wissenschaftler und Projektträger', 'Privatpersonen, Institutionen', NULL, NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie, Wissenschaftler, Nachwuchs- wissenschaftler und Projektträger", "GESUCHSTELLENDE": "Privatpersonen, Institutionen"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (70, 'jubilaumsstiftung-der-schweizer-reisekasse', 'Jubiläumsstiftung der Schweizer Reisekasse', 57, 'Die Stiftung bezweckt die finanzielle Unterstützung von Massnahmen, die dazu beitragen, wirtschaftlich und sozial benachteiligten Menschen Ferien in der Schweiz zu ermöglichen und zu erleichtern. Bezugsberechtigt sind vor allem Be hinderte, die sich aus eigenen Mitteln keine Ferien leisten können. Gesuche für Gruppenferien können vor Ferienbeginn von Behindertenverbänden, Sozialämtern und ähnlichen Institutionen eingereicht werden. Für Auslandferien können keine Beiträge gewährt werden.', 'Ferien für wirtschaftlich und sozial benachteiligte Menschen · Neuengasse 15 Postfach · 3001 Bern · Tel. 031 329 66 80 · soziales@reka.ch · www.reka.ch', 'Ferien für wirtschaftlich und sozial benachteiligte Menschen · Neuengasse 15 Postfach · 3001 Bern · Tel. · · www.', '3001', 'Bern · Tel. 031 329 66 80 · soziales@reka.ch · www.reka.ch', '["031 329 66 80"]', '["soziales@reka.ch"]', '["reka.ch", "www.reka.ch"]', 'Menschen mit Behinderung, sozial Benachteiligte', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Gesuche müssen frühzeitig vor den geplanten Ferienlagern einge- reicht werden. Die zugesagten Unterstützungsbeiträge werden nach Einreichen der Schlussabrechnung ausbezahlt.', 'Jubiläumsstiftung der Schweizer Reisekasse, Elisabeth Ziörjen, Neuengasse 15, 3001 Bern', 'Budget, Teilnehmerliste, Kostenabrechnung, Betreuerliste', '{"BEILAGEN": "Budget, Teilnehmerliste, Kostenabrechnung, Betreuerliste", "ZIELGRUPPE": "Menschen mit Behinderung, sozial Benachteiligte", "EMPFANGSSTELLE": "Jubiläumsstiftung der Schweizer Reisekasse, Elisabeth Ziörjen, Neuengasse 15, 3001 Bern", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Gesuche müssen frühzeitig vor den geplanten Ferienlagern einge- reicht werden. Die zugesagten Unterstützungsbeiträge werden nach Einreichen der Schlussabrechnung ausbezahlt."}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (71, 'jugendhilfeverein-des-bezirkes-dielsdorf', 'Jugendhilfeverein des Bezirkes Dielsdorf', 58, 'Unterstützung von benachteiligten Kindern und Jugendlichen wohnhaft im Bezirk Dielsdorf.
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (72, 'kaspar-spoerry-stiftung', 'Kaspar Spoerry Stiftung', 58, 'Die Stiftung richtet Vergabungen aus an radsportinteressierte Menschen mit Behinderungen, gleich welchen Alters und welcher Nationalität, insbesondere durch Unterstützung des Erwerbs von Menschen mit Behinderungenngerechten Fahrrädern oder Zubehör.', 'c/o Vreni Spoerry, Claridenstrasse 5, 8810 Horgen, 044 725 07 38', 'c/o Vreni Spoerry, Claridenstrasse 5, 8810 Horgen', '8810', 'Horgen', '["044 725 07 38"]', '[]', '[]', 'Menschen mit Behinderungen Sportinteressierte', 'Privatpersonen', 'Ganzes Jahr. Auszahlung erfolgt in der Regel nur 2-mal jährlich', NULL, 'Kontoangaben, Kostenvoranschlag, begründetes Gesuch', '{"BEILAGEN": "Kontoangaben, Kostenvoranschlag, begründetes Gesuch", "ZIELGRUPPE": "Menschen mit Behinderungen Sportinteressierte", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Auszahlung erfolgt in der Regel nur 2-mal jährlich"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
