INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (75, 'krokop-stiftung', 'Krokop-Stiftung', 59, 'Unterstützung gemeinnütziger Fürsorge für Kinder und Rettungsdienste, gemeinnütziger Trägerschaften und Organisationen wie Kinderheime, Waisenhäuser, Lehrlingsheime, Waisen- oder Scheidungskinder, Jugend- und Nachwuchsförderung, Beiträge an anerkannte Rettungsdienste.', 'c/o Treuhandbüro B. Sutter & Partner, Flurstrasse 32, 8048 Zürich, 044 462 69 90, b.honegger@sutter-partner.ch', 'c/o Treuhandbüro B. Sutter & Partner, Flurstrasse 32, 8048 Zürich', '8048', 'Zürich', '["044 462 69 90"]', '["b.honegger@sutter-partner.ch"]', '["sutter-partner.ch"]', NULL, 'Institutionen', 'Ganzes Jahr', NULL, 'Arztzeugnis, Ausbildungsbestätigung, Referenzen
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (76, 'kurt-fontheim-stiftung', 'Kurt Fontheim-Stiftung', 59, 'Förderung der Erstausbildung junger Menschen', 'c/o Sielva Management SA, Gubelstrasse 11, 6300 Zug', 'c/o Sielva Management SA, Gubelstrasse 11, 6300 Zug', '6300', 'Zug', '[]', '[]', '[]', 'Jugend, Ausbildung', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kontoangaben, Lebenslauf, Vermögensverhältnisse (inkl. Eltern), Aussichten nach Berufsausbildung, genaue Angaben über Einnahmen und Ausgaben (Budget), Steuererklärung (Eltern, eigene)', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Lebenslauf, Vermögensverhältnisse (inkl. Eltern), Aussichten nach Berufsausbildung, genaue Angaben über Einnahmen und Ausgaben (Budget), Steuererklärung (Eltern, eigene)", "ZIELGRUPPE": "Jugend, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
