INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (78, 'lotteriefonds-des-kantons-zurich', 'Lotteriefonds des Kantons Zürich', 60, 'Einmalige Beiträge an ausserordentliche gemeinnützige und wohltätige bzw. kulturelle Projekte mit mindestens regionaler Ausstrahlung, für die keine gesetzlichen Ansprüche geltend gemacht werden können. Einzelpersonen werden nicht berücksichtigt.
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (79, 'luchsinger-haggenmacher-stiftung', 'Luchsinger-Haggenmacher Stiftung', 60, 'Die Stiftung bezweckt die Ausrichtung von Leistungen an Kinder und Jugendliche in der ganzen Schweiz, welche in irgendeiner Art behindert oder Waisen sind.', 'c/o Schweiz. Gemeinnützige Gesellschaft (SGG), Schaffhauserstrasse 7, 8042 Zürich, 044 366 50 30, info@sgg-ssup.ch', 'c/o Schweiz. Gemeinnützige Gesellschaft (SGG), Schaffhauserstrasse 7, 8042 Zürich', '8042', 'Zürich', '["044 366 50 30"]', '["info@sgg-ssup.ch"]', '["sgg-ssup.ch"]', 'Jugend & Familie, Menschen mit Behinderungen Kinder und Waisen in der ganzen Schweiz (bis zum Alter von 25 Jahren)', 'Privatpersonen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie, Menschen mit Behinderungen Kinder und Waisen in der ganzen Schweiz (bis zum Alter von 25 Jahren)", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (80, 'luiza-penha-walter-renteiro-stiftung-bezirk-meilen', 'Luiza Penha Walter-Renteiro-Stiftung – Bezirk Meilen', 60, 'Die Stiftung wurde errichtet zur Unterstützung von Kindern und Jugendlichen des Bezirks Meilen. Im Rahmen des Stiftungszweckes können Zuwendungen an Institutionen mit gemeinnütziger Zielsetzung ausgerichtet werden. Zudem werden Kinder und Jugendliche unterstützt, für welche eine nötige Anschaffung, eine Freizeitaktivität oder entwicklungsunterstützende Rahmenbedingungen weder aus eigenen Mitteln noch durch die öffentliche Hand finanzierbar sind. Junge Erwachsene in Ausbildung können aus dem Legat Willy Blaser unterstützt werden.', 'c/o kjz Meilen, General-Wille-Strasse 59, 8706 Feldmeilen', 'c/o kjz Meilen, General-Wille-Strasse 59, 8706 Feldmeilen', '8706', 'Feldmeilen', '[]', '[]', '[]', 'Kinder, Jugendliche sowie junge Erwachsene bis längstens 20 J. mit Wohnsitz im Bezirk Meilen', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kontoangaben, Referenzen, Finanzierungsplan', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen, Finanzierungsplan", "ZIELGRUPPE": "Kinder, Jugendliche sowie junge Erwachsene bis längstens 20 J. mit Wohnsitz im Bezirk Meilen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (81, 'martha-bock-stiftung', 'Martha Bock Stiftung', 61, 'Zweck der Stiftung ist es, im Kanton Zürich wohnhafte bedürftige reformierte Be- tagte und Behinderte zu unterstützen und ihr Los zu verschönern. Ebenso die Un- terstützung von gemeinnützigen Institutionen, die dem vorstehenden Zweck die- nen. Es können auch Projekte, die diesem Zweck dienen, unterstützt werden.', 'Pro Senectute Kanton Zürich · c/o Bruno Gemperle · Forchstrasse 145 · 8032 Zürich info@martha-bock-stiftung.ch · www.martha-bock-stiftung.ch', 'Pro Senectute Kanton Zürich · c/o Bruno Gemperle · Forchstrasse 145 · 8032 Zürich · www.', '8032', 'Zürich info@martha-bock-stiftung.ch · www.martha-bock-stiftung.ch', '[]', '["info@martha-bock-stiftung.ch"]', '["martha-bock-stiftung.ch", "www.martha-bock-stiftung.ch"]', 'Ältere Menschen, Menschen mit Behinderungen, Gesundheit/Krankheit, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', 'Stiftungsadresse', 'Kontoangaben', '{"BEILAGEN": "Kontoangaben", "ZIELGRUPPE": "Ältere Menschen, Menschen mit Behinderungen, Gesundheit/Krankheit, Armut", "EMPFANGSSTELLE": "Stiftungsadresse", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (82, 'max-rudolf-forrer-stiftung', 'Max Rudolf Forrer-Stiftung', 61, 'Zinsen und Kapital der Stiftung dienen der Hilfe an bedürftige Personen, die wegen Augenleiden ärztliche Hilfe in Anspruch nehmen müssen oder die wegen Verlustes des Augenlichtes bedürftig geworden sind. Sie können ferner zur Anschaffung von Apparaten Verwendung finden, die eine bessere Behandlung von Augenkranken ermöglichen.', 'Abteilung Soziales · Bahnhofstrasse 17 · 8610 Uster · T. 044 944 73 13 · soziales@uster.ch', 'Abteilung Soziales · Bahnhofstrasse 17 · 8610 Uster · T. ·', '8610', 'Uster · T. 044 944 73 13 · soziales@uster.ch', '["044 944 73 13"]', '["soziales@uster.ch"]', '["uster.ch"]', 'Primär Einwohner und Bürger der Stadt Uster, unter engen Voraussetzungen ein weiterer Kreis von Bedürftigen, vornehmlich im Kanton Zürich, welche aufgrund von Augenkrankheiten finanzielle Hilfe benötigen.', 'Privatpersonen, Institutionen', 'Ganzes Jahr', 'Stiftungsadresse oder: Max Rudolf Forrer-Stiftung, c/o Herr Dr. med. Thai-Nia Heidelberg, Bankstrasse 8, 8610 Uster / oder: Max Rudolf Forrer-Stiftung, c/o Frau Dr. med. Eva Serafino-Skalsky, Zürichstrasse 1, 8610 Uster', 'Arztzeugnis, Kontoangaben, Nachweise Bedürftigkeit, Nachweis Kosten, für welche um finanzielle Beitragsleistung ersucht wird', '{"BEILAGEN": "Arztzeugnis, Kontoangaben, Nachweise Bedürftigkeit, Nachweis Kosten, für welche um finanzielle Beitragsleistung ersucht wird", "ZIELGRUPPE": "Primär Einwohner und Bürger der Stadt Uster, unter engen Voraussetzungen ein weiterer Kreis von Bedürftigen, vornehmlich im Kanton Zürich, welche aufgrund von Augenkrankheiten finanzielle Hilfe benötigen.", "EMPFANGSSTELLE": "Stiftungsadresse oder: Max Rudolf Forrer-Stiftung, c/o Herr Dr. med. Thai-Nia Heidelberg, Bankstrasse 8, 8610 Uster / oder: Max Rudolf Forrer-Stiftung, c/o Frau Dr. med. Eva Serafino-Skalsky, Zürichstrasse 1, 8610 Uster", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (83, 'max-und-erika-gideon-stiftung', 'Max und Erika Gideon-Stiftung', 62, 'Unterstützung von Bedürftigen, Behinderten und Kranken. Unterstützung kultureller Aufgaben wie Förderung von Literatur, Kunst, Wissenschaft. Konfession: spielt keine Rolle. Wohnsitz: Kanton Zürich. Auszahlung: Nur einmalige Zahlungen und nicht an Privatpersonen direkt.', 'c/o E. Gideon · Seeblickstrasse 25 · 8038 Zürich', 'c/o E. Gideon · Seeblickstrasse 25 · 8038 Zürich', '8038', 'Zürich', '[]', '[]', '[]', 'Betagte, Behinderte, Kranke, Soziale Institutionen, Gesundheit, Armut, Kultur, Ausbildung', 'Institutionen', '1. Quartal jeden Jahres', NULL, 'Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, Referenzen', '{"BEILAGEN": "Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, Referenzen", "ZIELGRUPPE": "Betagte, Behinderte, Kranke, Soziale Institutionen, Gesundheit, Armut, Kultur, Ausbildung", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "1. Quartal jeden Jahres"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
