INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (85, 'monique-dornonville-de-la-cour-stiftung', 'Monique Dornonville de la Cour-Stiftung', 62, 'Die Monique Dornonville de la Cour-Stiftung bezweckt die Unterstützung und Förderung von Tätigkeiten zur Linderung menschlicher Not in der Schweiz. Die Stiftung unterstützt gemeinnützige Hilfsorganisationen, die unter anderem in den nachfolgend beschriebenen Bereichen tätig sind:
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (86, 'moriz-und-elsa-von-kuffner-stiftung', 'Moriz und Elsa von Kuffner-Stiftung', 63, 'Stipendien an begabte Jugendliche, insbesondere solche aus Berg- und Randregionen während ihres Studiums an einer schweizerischen Universität, insbesondere an der ETH Zürich und der Universität Zürich; Zuwendungen an privatrechtlich organisierte schweizerische, namentlich zürcherische Sozialwerke; Stipendien an Pflegefachpersonen in Ausbildung; Unterstützung von Berggemeinden und Institutionen. Gemäss Stiftungsurkunde können nur Personen mit Schweizer Bürgerrecht und schweizerische Institutionen unterstützt werden.', 'c/o Schellenberg Wittmer · Löwenstrasse 19 · Postfach 2201 · 8021 Zürich Tel. 041 790 60 40 · info@kuffner.ch · www.kuffner.ch', 'c/o Schellenberg Wittmer · Löwenstrasse 19 · Postfach 2201 · 8021 Zürich Tel. · · www.', '8021', 'Zürich Tel. 041 790 60 40 · info@kuffner.ch · www.kuffner.ch', '["041 790 60 40"]', '["info@kuffner.ch"]', '["kuffner.ch", "www.kuffner.ch"]', 'Soziale Institutionen, Pflegefachpersonen in Ausbildung, Studierende an Universitäten, Berggemeinden und Institutionen', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Siehe Website unter Menu p Termine. Je nach Bereich das richtige Formular wählen (bei Fragen bitte anrufen oder eine E-Mail schreiben). Spezialformular anfordern', 'Gesuche per Post einreichen (keine Express-Post)', 'Ausbildungsbestätigung, Kontoangaben, Beilagen gemäss Formular', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Beilagen gemäss Formular", "ZIELGRUPPE": "Soziale Institutionen, Pflegefachpersonen in Ausbildung, Studierende an Universitäten, Berggemeinden und Institutionen", "EMPFANGSSTELLE": "Gesuche per Post einreichen (keine Express-Post)", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Siehe Website unter Menu p Termine. Je nach Bereich das richtige Formular wählen (bei Fragen bitte anrufen oder eine E-Mail schreiben). Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (87, 'orphelina-stiftung', 'Orphelina-Stiftung', 63, 'Die Stiftung bezweckt die Förderung der Wohlfahrt von sich dauernd oder vorüber- gehend in der Schweiz aufhaltenden hilfsbedürftigen Kindern ohne Ansehen der Religion oder der Nationalität. Gesuche sind über einen örtlichen Sozial- dienst an unsere Stiftungsadresse einzureichen. Es werden Gesuche mit einem Minimalbetrag von Fr. 2000.– geprüft.', 'c/o Schweiz. Gemeinnützige Gesellschaft · Schaffhauserstrasse 7 · 8042 Zürich Tel. 044 366 50 30 · info@sgg-ssup.ch · www.sgg-ssup.ch', 'c/o Schweiz. Gemeinnützige Gesellschaft · Schaffhauserstrasse 7 · 8042 Zürich Tel. · · www.', '8042', 'Zürich Tel. 044 366 50 30 · info@sgg-ssup.ch · www.sgg-ssup.ch', '["044 366 50 30"]', '["info@sgg-ssup.ch"]', '["sgg-ssup.ch", "www.sgg-ssup.ch"]', 'Kinder und Jugendliche, Wohlfahrt', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Vollständige kurze Schilderung des Falles, inklusive Personalien, Budget, Zweck der nachgefragten Summe. Im Zweifelsfall gibt die Seite www.sgg-ssup.ch präziserere Auskunft', '{"BEILAGEN": "Vollständige kurze Schilderung des Falles, inklusive Personalien, Budget, Zweck der nachgefragten Summe. Im Zweifelsfall gibt die Seite www.sgg-ssup.ch präziserere Auskunft", "ZIELGRUPPE": "Kinder und Jugendliche, Wohlfahrt", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (88, 'oscar-seeger-stiftung', 'Oscar Seeger-Stiftung', 64, 'Ausrichtung angemessener Zuwendungen an gemeinnützige Organisationen in der Gemeinde Küsnacht sowie in der Stadt Zürich, insbesondere auch die Ausrichtung von Zuwendungen, welche die finanzielle Besserstellung reformierter Krankenschwestern zum Ziele haben oder der Unterstützung der «Stiftung für das Alter» dienen.', 'c/o Gemeinde Küsnacht · Obere Dorfstrasse 32 · 8700 Küsnacht ZH Tel. 044 913 12 01 · finanzen@kuesnacht.ch', 'c/o Gemeinde Küsnacht · Obere Dorfstrasse 32 · 8700 Küsnacht ZH Tel. ·', '8700', 'Küsnacht ZH Tel. 044 913 12 01 · finanzen@kuesnacht.ch', '["044 913 12 01"]', '["finanzen@kuesnacht.ch"]', '["kuesnacht.ch"]', 'Institutionen, keine Privatpersonen', 'Institutionen', 'Ganzes Jahr', NULL, 'Kontoangaben, Projektbeschrieb und Finanzierung, Infos über Organisation, Jahresrechnung', '{"BEILAGEN": "Kontoangaben, Projektbeschrieb und Finanzierung, Infos über Organisation, Jahresrechnung", "ZIELGRUPPE": "Institutionen, keine Privatpersonen", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (89, 'paulie-und-fridolin-dublin-stiftung', 'Paulie und Fridolin Düblin Stiftung', 65, 'Die Stiftung fördert sowohl die ambulante Therapie und Betreuung von Menschen mit Demenzerkrankungen in ihrem häuslichen Umfeld als auch teilstationäre Betreuungsmöglichkeiten. Unterstützung:
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (90, 'paul-peter-alden-stiftung', 'Paul Peter Alden Stiftung', 64, 'Die Stiftung, welche im Jahr 2010 errichtet wurde, unterstützt physisch, psychisch und geistig behinderte Kinder und Jugendliche in der Schweiz. Sie finanziert Aus- und Weiterbildungen, Therapien, Heil- und Hilfsmittel sowie Wiedereingliederungs-Massnahmen, wo Leistungen der öffentlichen Hand nicht oder nur ungenügend erhältlich sind. Stiftungsmittel kommen nicht nur Einzelpersonen, sondern auch gemeinnützigen Institutionen oder Organisationen im Bereich Jugendarbeit zugute.', 'c/o Wenger & Vieli AG · Dufourstrasse 56 · 8008 Zürich · 058 958 58 58 sekretariat@alden-stiftung.ch · www.alden-stiftung.ch', 'c/o Wenger & Vieli AG · Dufourstrasse 56 · 8008 Zürich · · www.', '8008', 'Zürich · 058 958 58 58 sekretariat@alden-stiftung.ch · www.alden-stiftung.ch', '["058 958 58 58"]', '["sekretariat@alden-stiftung.ch"]', '["alden-stiftung.ch", "www.alden-stiftung.ch"]', 'Physisch, psychisch und geistig behinderte Kinder und Jugendliche in der Schweiz', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', 'Paul Peter Alden Stiftung, c/o Frau lic. phil.I Elisabeth Boxler, Oststrasse 1, 8400 Winterthur', 'Kontoangaben', '{"BEILAGEN": "Kontoangaben", "ZIELGRUPPE": "Physisch, psychisch und geistig behinderte Kinder und Jugendliche in der Schweiz", "EMPFANGSSTELLE": "Paul Peter Alden Stiftung, c/o Frau lic. phil.I Elisabeth Boxler, Oststrasse 1, 8400 Winterthur", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (141, 'stiftung-fur-hochbegabte-kinder', 'Stiftung für hochbegabte Kinder', 83, 'Beratung für Eltern mit hochbegabten Kindern und Schulprojekte für Begabungs- und Begabtenförderung.', 'Untere Zäune 3, 8001 Zürich, 044 273 05 56 (Geschäftsstelle), 061 411 10 11 (Anlaufstelle Hochbegabung), stiftung@hochbegabt.ch, www.hochbegabt.ch', 'Untere Zäune 3, 8001 Zürich, (Geschäftsstelle), (Anlaufstelle Hochbegabung), www.', '8001', 'Zürich', '["044 273 05 56", "061 411 10 11"]', '["stiftung@hochbegabt.ch"]', '["hochbegabt.ch", "www.hochbegabt.ch"]', 'Eltern mit hochbegabten Kindern in der Schweiz', 'Privatpersonen, Institutionen', NULL, NULL, NULL, '{"ZIELGRUPPE": "Eltern mit hochbegabten Kindern in der Schweiz", "GESUCHSTELLENDE": "Privatpersonen, Institutionen"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (91, 'paul-schiller-stiftung', 'Paul Schiller Stiftung', 65, 'Die Paul Schiller Stiftung wurde zum Zwecke errichtet, gemeinnützige Werke aller Art zu schaffen, zu betreiben oder zu fördern, wobei auch über das Stiftungskapital verfügt werden kann. Die Stiftung kann auch Vergabungen zugunsten von Tieren oder zoologischen Gärten tätigen.', 'Sekretariat · c/o BDO AG · Feldmoosstrasse 12 · 8853 Lachen SZ · Tel. 055 451 52 30 info@paul-schiller-stiftung.ch · www.paul-schiller-stiftung.ch', 'Sekretariat · c/o BDO AG · Feldmoosstrasse 12 · 8853 Lachen SZ · Tel. · www.', '8853', 'Lachen SZ · Tel. 055 451 52 30 info@paul-schiller-stiftung.ch · www.paul-schiller-stiftung.ch', '["055 451 52 30"]', '["info@paul-schiller-stiftung.ch"]', '["paul-schiller-stiftung.ch", "www.paul-schiller-stiftung.ch"]', 'Armut', 'Institutionen', 'Ganzes Jahr', 'Gesuche sind an die Adresse der Stiftung zu richten', NULL, '{"ZIELGRUPPE": "Armut", "EMPFANGSSTELLE": "Gesuche sind an die Adresse der Stiftung zu richten", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
