INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (93, 'pestalozzi-stiftung', 'Pestalozzi-Stiftung', 66, 'Förderung der beruflichen Aus- und Weiterbildung von Jugendlichen und jungen Erwachsenen aus schweizerischen Berggegenden durch Gewährung von Stipendien und zinslosen Darlehen.', 'Frauenmünsterstrasse 17 · Postfach · 8024 Zürich · Tel. 044 210 40 80 office@pestalozzi-stiftung.ch · www.pestalozzi-stiftung.ch', 'Frauenmünsterstrasse 17 · Postfach · 8024 Zürich · Tel. · www.', '8024', 'Zürich · Tel. 044 210 40 80 office@pestalozzi-stiftung.ch · www.pestalozzi-stiftung.ch', '["044 210 40 80"]', '["office@pestalozzi-stiftung.ch"]', '["pestalozzi-stiftung.ch", "www.pestalozzi-stiftung.ch"]', 'Jugend & Familie (Jugendliche und junge Erwachsene bis 35 Jahre – Erstgesuch muss vor dem 30. Altersjahr erfolgen), Ausbildung', 'Privatpersonen', 'Ganzes Jahr. Informationen unter www.pestalozzi-stiftung.ch. Spezialformular anfordern', NULL, 'Ausbildungsbestätigung, Kontoangaben, Steuernachweis, kantonaler Stipendien- entscheid (siehe Seite 4 des Antragsformulars)
