INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (95, 'pro-infirmis', 'Pro Infirmis', 66, 'Menschen mit Behinderung sind oft mit Auslagen konfrontiert, die den Rahmen der Leistungen der Sozialversicherungen sprengen. Denn: Behinderung ist in der Schweiz nach wie vor ein Armutsrisiko. Pro Infirmis Zürich berät und begleitet Sie in dieser Situation und informiert über die Bestimmungen.', 'Hohlstrasse 560 · Postfach · 8048 Zürich · Tel. 058 775 25 25 · zuerich@proinfirmis.ch www.proinfirmis.ch', 'Hohlstrasse 560 · Postfach · 8048 Zürich · Tel. · www.', '8048', 'Zürich · Tel. 058 775 25 25 · zuerich@proinfirmis.ch www.proinfirmis.ch', '["058 775 25 25"]', '["zuerich@proinfirmis.ch"]', '["proinfirmis.ch", "www.proinfirmis.ch"]', 'Menschen mit Behinderung', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Menschen mit Behinderung", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (96, 'pro-juventute', 'Pro Juventute', 67, 'Pro Juventute unterstützt Kinder und Jugendliche mit ihren Eltern auf dem Weg zu selbst- und sozialverantwortlichen Persönlichkeiten. Mit vielfältigen Angeboten in den Bereichen «Medien & Konsum», «Bildung & Beruf» sowie «Freizeit & Gesundheit» setzt sich Pro Juventute für Kinder und Jugendliche in der Schweiz ein – vor Ort, direkt und nachhaltig. Über 300''000 Kinder in der ganzen Schweiz profitieren jährlich von Angeboten wie der Pro Juventute Beratung + Hilfe 147 oder den Pro Juventute Elternbriefen. Pro Juventute ist eine private, politisch und konfessionell unabhängige gemeinnützige Organisation. Mit der nationalen Stiftung und den regionalen Vereinen in den Kantonen mit ihren freiwilligen Mitarbeiterinnen und Mitarbeitern ist Pro Juventute in der ganzen Schweiz präsent. In ihrer Arbeit orientiert sie sich an den Grundsätzen der UNO-Kinderrechtskonvention.', 'Thurgauerstrasse 39 · Postfach · 8050 Zürich · Tel. 044 256 77 77 info@projuventute.ch · www.projuventute.ch', 'Thurgauerstrasse 39 · Postfach · 8050 Zürich · Tel. · www.', '8050', 'Zürich · Tel. 044 256 77 77 info@projuventute.ch · www.projuventute.ch', '["044 256 77 77"]', '["info@projuventute.ch"]', '["projuventute.ch", "www.projuventute.ch"]', 'Pro Juventute unterstützt Kinder und Jugendliche mit ihren Eltern auf dem Weg zu selbst- und sozialverantwortlichen Persönlichkeiten.', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', 'Pro Juventute unterstützt Witwen und Witwer mit Kindern sowie Halb- und Vollwaisen in finanzieller Not. Weitere Angaben zu den Gesuchsempfangsstellen finden Sie auf www.projuventute.ch -> In Ihrer Region', NULL, '{"ZIELGRUPPE": "Pro Juventute unterstützt Kinder und Jugendliche mit ihren Eltern auf dem Weg zu selbst- und sozialverantwortlichen Persönlichkeiten.", "EMPFANGSSTELLE": "Pro Juventute unterstützt Witwen und Witwer mit Kindern sowie Halb- und Vollwaisen in finanzieller Not. Weitere Angaben zu den Gesuchsempfangsstellen finden Sie auf www.projuventute.ch -> In Ihrer Region", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (98, 'reka-stiftung-ferienhilfe', 'Reka Stiftung Ferienhilfe', 68, 'Die Reka Stiftung Ferienhilfe ermöglicht armutsbetroffenen Familien und Alleinerziehenden mit Kindern bis 16 Jahren eine Ferienwoche für 200 Franken in der Schweiz. Gleichzeitig unterstützt sie Ferienlager für Kinder und Jugendliche mit Beeinträchtigungen finanziell.', 'Ferien für wirtschaftlich u. sozial benachteiligte Menschen, Neuengasse 15, Postfach, 3001 Bern, 031 329 66 80, ferienhilfe@reka.ch, www.reka.ch', 'Ferien für wirtschaftlich u. sozial benachteiligte Menschen, Neuengasse 15, Postfach, 3001 Bern,, www.', '3001', 'Bern', '["031 329 66 80"]', '["ferienhilfe@reka.ch"]', '["reka.ch", "www.reka.ch"]', 'Armutsbetroffene Familien und Alleinerziehende mit Kindern bis 16 Jahre, Schweizer Institutionen, die Ferienlager für Kinder und Jugendliche mit Beeinträchtigungen organisieren.', 'Privatpersonen, Institutionen', 'Ferienwochen für 200 Franken bis 3 Wochen vor Ferienbeginn, Ferienlager bis Ende Juni.', 'Ferien für wirtschaftlich u. sozial benachteiligte Menschen, Neuengasse 15, Postfach, 3001 Bern', 'Budget, Teilnehmerliste, Kostenabrechnung, Betreuerliste', '{"BEILAGEN": "Budget, Teilnehmerliste, Kostenabrechnung, Betreuerliste", "ZIELGRUPPE": "Armutsbetroffene Familien und Alleinerziehende mit Kindern bis 16 Jahre, Schweizer Institutionen, die Ferienlager für Kinder und Jugendliche mit Beeinträchtigungen organisieren.", "EMPFANGSSTELLE": "Ferien für wirtschaftlich u. sozial benachteiligte Menschen, Neuengasse 15, Postfach, 3001 Bern", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ferienwochen für 200 Franken bis 3 Wochen vor Ferienbeginn, Ferienlager bis Ende Juni."}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (99, 'robert-stahel-stiftung', 'Robert Stahel-Stiftung', 68, 'Die Stiftung bezweckt, Kindern von Bürgern und Einwohnern (mehr als 3 Jahre in der Gemeinde Turbenthal ansässig) durch einmalige oder periodische Beiträge eine Berufslehre zu ermöglichen (auch Besuch einer höheren Schule). Förderung des landwirtschaftlichen Nachwuchses. Keine Beiträge für 10. Schuljahr.', 'Walter Fehr, Schürlistrasse 4, 8488 Turbenthal, 079 702 38 65', 'Walter Fehr, Schürlistrasse 4, 8488 Turbenthal', '8488', 'Turbenthal', '["079 702 38 65"]', '[]', '[]', 'Jugend & Familie, Ausbildung', 'Privatpersonen', 'Ganzes Jahr bis Ende Mai. Spezialformular anfordern', NULL, 'Ausbildungsbestätigung, Steuerausweis', '{"BEILAGEN": "Ausbildungsbestätigung, Steuerausweis", "ZIELGRUPPE": "Jugend & Familie, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr bis Ende Mai. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (100, 'rokj-stadt-zurich-rotary-fur-kinder-und-jugendliche', 'ROKJ Stadt Zürich – Rotary für Kinder und Jugendliche', 69, 'ROKJ Stadt Zürich fördert die Integration von sozial oder wirtschaftlich benachteiligten Kindern und Jugendlichen in der Stadt Zürich. Das Ziel ist, dass auch sie ihr Potenzial und ihre Talente entwickeln und altersgemässe Betätigungen ausüben können. Da wo staatliche und andere Hilfeleistungen nicht mehr greifen, will ROKJ mit gezielten Beiträgen betroffenen Kindern und Jugendlichen zusätzliche Chancen und Möglichkeiten eröffnen. Weitere ROKJ-Stellen im Kanton Zürich sind auf der Website ersichtlich.', 'ROKJ Stadt Zürich, 8000 Zürich, 044 558 79 51, info@rokj-stadtzuerich.ch, www.rokj.ch  Regionen  Zürich', 'ROKJ Stadt Zürich, 8000 Zürich,, Regionen Zürich', '8000', 'Zürich', '["044 558 79 51"]', '["info@rokj-stadtzuerich.ch"]', '["rokj-stadtzuerich.ch", "www.rokj.ch"]', 'Kinder und Jugendliche in der Stadt Zürich', 'Privatpersonen', 'Ganzes Jahr', 'www.rokj.ch  Regionen  Zürich', 'Gemäss Gesuchs-Formular (Steuererklärung, Lohnausweis, Mietvertrag usw.)
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (101, 'rolf-und-gertrud-waldmann-stiftung', 'Rolf und Gertrud Waldmann-Stiftung', 69, 'Zweck der Stiftung ist die Betreuung und/oder finanzielle Unterstützung armer Kinder und Jugendlicher, die im Kanton Zürich und Aargau Wohnsitz oder Aufenthalt haben, die physisch/geistig behindert oder psychisch geschädigt sind. Die Betreuung soll gemäss den pädagogischen Erkenntnissen nach Dr. Rudolf Steiner erfolgen.', 'c/o Rüsch Treuhand AG, Lehfrauenweg 10, Postfach 514, 8053 Zürich', 'c/o Rüsch Treuhand AG, Lehfrauenweg 10, Postfach 514, 8053 Zürich', '8053', 'Zürich', '[]', '[]', '[]', 'Jugend & Familie, Menschen mit Behinderungen, Kranke, Ausbildung', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Arztzeugnis, Kopie der letzten Steuererklärung, inkl. aktuelle Steuerrechnung', '{"BEILAGEN": "Arztzeugnis, Kopie der letzten Steuererklärung, inkl. aktuelle Steuerrechnung", "ZIELGRUPPE": "Jugend & Familie, Menschen mit Behinderungen, Kranke, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (102, 'rudolf-pohl-stiftung', 'Rudolf Pohl-Stiftung', 69, 'Die Stiftung bezweckt die Förderung der leiblichen, sittlichen und seelischen Armut von Schweizer Wehrmännern und deren Hinterbliebenen im Falle der Bedürftigkeit.', 'c/o Frau Sylvia Omura, Bauherrenstrasse 56, 8049 Zürich, 044 341 49 66, sylomura@bluewin.ch', 'c/o Frau Sylvia Omura, Bauherrenstrasse 56, 8049 Zürich', '8049', 'Zürich', '["044 341 49 66"]', '["sylomura@bluewin.ch"]', '["bluewin.ch"]', 'Angehörige des Militärs, Armut. Notlage, respektive Bedürfnis muss durch Militärdienst oder im Zusammenhang mit Militärdienst entstanden sein.', 'Privatpersonen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Angehörige des Militärs, Armut. Notlage, respektive Bedürfnis muss durch Militärdienst oder im Zusammenhang mit Militärdienst entstanden sein.", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (103, 'scharer-hofmann-stiftung', 'Schärer-Hofmann-Stiftung', 70, 'Zweck der Stiftung ist die Verwaltung und Äufnung des Stiftungsvermögens und die Verwendung desselben für in Horgen wohnhafte sozial bedürftige Kinder und Jugendliche sowie für die Jugendarbeit im Allgemeinen in der Gemeinde Horgen.', 'c/o Soziales Horgen, Alte Landstrasse 25 Postfach, 8810 Horgen, 044 728 42 57, mara.aquilone@horgen.ch', 'c/o Soziales Horgen, Alte Landstrasse 25 Postfach, 8810 Horgen', '8810', 'Horgen', '["044 728 42 57"]', '["mara.aquilone@horgen.ch"]', '["horgen.ch"]', 'Jugend & Familie, Ausländerinnen, Ausbildung', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kontoangaben, Angaben über finanzielle Verhältnisse (Vermögen, Einkommen)', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Angaben über finanzielle Verhältnisse (Vermögen, Einkommen)", "ZIELGRUPPE": "Jugend & Familie, Ausländerinnen, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (104, 'schmid-worner-stiftung-hongg', 'Schmid-Wörner-Stiftung Höngg', 70, 'Ursprünglich die Bürgergemeinde Höngg betreffend, heute zugunsten bedürftiger Bürger und Bürgerinnen der ehemaligen Gemeinde Höngg oder Personen, die seit mindestens zehn Jahren im Quartier Höngg wohnen, ferner für gemeinnützige Zwecke. Die Stiftung wird von einem Stiftungsrat verwaltet. Wohnsitz: Zürich-Höngg, Heimatort: Gemeindebürger von Zürich, Auszahlung: à fonds perdu. Einmalige und wiederholte Zahlungen.', 'c/o Bruno Dohner, Im Maas 16 a, 8049 Zürich', 'c/o Bruno Dohner, Im Maas 16 a, 8049 Zürich', '8049', 'Zürich', '[]', '[]', '[]', 'Ausbildung, Altersfürsorge, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Persönliches Schreiben', '{"BEILAGEN": "Persönliches Schreiben", "ZIELGRUPPE": "Ausbildung, Altersfürsorge, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (105, 'schweizer-kinderhilfswerk-kovive', 'Schweizer Kinderhilfswerk Kovive', 74, 'Kovive ist ein wichtiger Partner für Fachleute der sozialen Arbeit und zuweisende Stellen in der ergänzenden Betreuung und Förderung von sozial benachteiligten Kindern und Jugendlichen in der Schweiz.', 'Betreuungslösungen und Förderangebote für Kinder in der Schweiz, Unterlachenstrasse 12, 6005 Luzern, 041 249 20 80, info@kovive.ch, www.kovive.ch', 'Betreuungslösungen und Förderangebote für Kinder in der Schweiz, Unterlachenstrasse 12, 6005 Luzern,, www.', '6005', 'Luzern', '["041 249 20 80"]', '["info@kovive.ch"]', '["kovive.ch", "www.kovive.ch"]', 'Zuweisende Fachstellen der sozialen  Familienberatungsstellen, armutsbetroffene Jugendliche und ihre Familien in der Schweiz', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Betreuungslösungen für Kinder in der Schweiz: Anmeldung jederzeit möglich
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (106, 'schweiz-gemeinnutzige-gesellschaft', 'Schweiz. Gemeinnützige Gesellschaft', 70, 'Einzelfallhilfe für alle Bedürftigen in der Schweiz. Vollständige Gesuche werden nur über kommunale Sozialdienste oder über Stellen mit ähnlicher Funktion angenommen. Es werden in der Regel nur Gesuche über einen Minimalbetrag von Fr. 2000.-- geprüft. Ein Beitrag wird nur gesprochen, sofern ein Nachweis vorliegt über Steuerbefreiung oder ein Steuererlass in mindestens gleicher Höhe wie die beantragte Summe. Bei der Unterstützung von sozialen Institutionen werden nationale oder überregionale Projekte berücksichtigt, jedoch keine Betriebsbeiträge ausbezahlt.', 'Schaffhauserstrasse 7, Postfach, 8042 Zürich, 044 366 50 30, info@sgg-ssup.ch, www.sgg-ssup.ch', 'Schaffhauserstrasse 7, Postfach, 8042 Zürich,, www.', '8042', 'Zürich', '["044 366 50 30"]', '["info@sgg-ssup.ch"]', '["sgg-ssup.ch", "www.sgg-ssup.ch"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr laufend', 'www.sgg-ssup.ch  Gesuche stellen', 'Angaben zur persönlichen Situation der/des Begünstigten, Nachweis über die Mitbeteiligung anderer Hilfswerke, Angaben über den Verwendungszweck der Gelder', '{"BEILAGEN": "Angaben zur persönlichen Situation der/des Begünstigten, Nachweis über die Mitbeteiligung anderer Hilfswerke, Angaben über den Verwendungszweck der Gelder", "ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen, Armut", "EMPFANGSSTELLE": "www.sgg-ssup.ch  Gesuche stellen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr laufend"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (107, 'schweiz-hilfe-fur-mutter-und-kind-shmk', 'Schweiz. Hilfe für Mutter und Kind (SHMK)', 71, 'Die Schweizerische Hilfe für Mutter und Kind (SHMK) ist eine gemeinnützige, steuerbefreite und unabhängige Stiftung und leistet Beratung und Direkthilfe an Frauen, Paare und Familien, die durch Schwangerschaft oder Geburt eines Kindes in Not geraten. Sie setzt sich für eine kinderfreundliche Mentalität in der Gesellschaft und für die Solidarität mit Mutter und Kind ein.', 'Postfach, 4142 Münchenstein, 061 703 77 77 (Sekretariat), 0800 811 100 (Helpline gratis), helpline@shmk.ch, www.shmk.ch', 'Postfach, 4142 Münchenstein, (Sekretariat), 0800 811 100 (Helpline gratis), www.', '4142', 'Münchenstein', '["061 703 77 77"]', '["helpline@shmk.ch"]', '["shmk.ch", "www.shmk.ch"]', 'Jugend & Familie, Ausländer/innen, Armut, Frauen, Paare und Familien, die durch Schwangerschaft und Geburt in Not geraten sind', 'Privatpersonen', 'Ganzes Jahr', 'Schweiz. Hilfe für Mutter und Kind (SHMK), Helpline, Postfach, 4011 Basel', 'Bei Schwangerschaft: Nachweis', '{"BEILAGEN": "Bei Schwangerschaft: Nachweis", "ZIELGRUPPE": "Jugend & Familie, Ausländer/innen, Armut, Frauen, Paare und Familien, die durch Schwangerschaft und Geburt in Not geraten sind", "EMPFANGSSTELLE": "Schweiz. Hilfe für Mutter und Kind (SHMK), Helpline, Postfach, 4011 Basel", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (108, 'schweiz-lungenstiftung', 'Schweiz. Lungenstiftung', 71, 'Verhütung und Bekämpfung von Tuberkulose und Lungenkrankheiten
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (120, 'sozialdepartement-der-stadt-zurich-fondsverwaltung', 'Sozialdepartement der Stadt Zürich – Fondsverwaltung', 76, 'Verschiedene Fonds: Einmalige Hilfeleistungen an vorübergehend in Not geratene Einwohnerinnen und Einwohner oder Stadtbürgerinnen und Stadtbürger der Stadt Zürich. Die Fonds sind für verschiedene Hilfeleistungen möglich.', 'Postfach, 8036 Zürich, 044 412 62 02, 044 412 60 22', 'Postfach, 8036 Zürich', '8036', 'Zürich', '["044 412 62 02", "044 412 60 22"]', '[]', '[]', 'Jugend & Familie, Ältere Menschen, Ausländer/innen, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', 'Das Gesuchsformular sowie entsprechende Auskünfte sind bei der Fondsverwaltung der Stadt Zürich unter 044 412 62 02 erhältlich.', NULL, '{"ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Ausländer/innen, Armut", "EMPFANGSSTELLE": "Das Gesuchsformular sowie entsprechende Auskünfte sind bei der Fondsverwaltung der Stadt Zürich unter 044 412 62 02 erhältlich.", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (109, 'schweiz-stiftung-fur-berufsmusiker-innen', 'Schweiz. Stiftung für Berufsmusiker/innen', 72, 'Die Stiftung fördert das schweizerische Musikleben durch die Förderung und Unterstützung von Berufsmusiker/innen, deren Ausbildung und Projekte. Sie fördert den Berufsnachwuchs und kann an in Not geratene Berufsmusiker/innen sowie an ihre Angehörigen Unterstützungsleistungen ausrichten. Die Gesuche werden 4x jährlich geprüft. Fristen: Ende Februar, Mai, August, November. Berücksichtigt werden Berufsmusiker/innen oder angehende Berufsmusiker/innen in Ausbildung. Die Berufsmusiker/innen müssen SMV-Mitglied sein. Bei Ensembles muss mindestens die Hälfte der MusikerInnen Mitglied des SMV sein.', 'SMV Schweizerischer Musikerverband, Kasernenstrasse 15, 8004 Zürich, 043 322 05 22, info@smv.ch, www.smv.ch/service/smv-stiftung', 'SMV Schweizerischer Musikerverband, Kasernenstrasse 15, 8004 Zürich,, www./service/smv-stiftung', '8004', 'Zürich', '["043 322 05 22"]', '["info@smv.ch"]', '["smv.ch", "www.smv.ch/service/smv-stiftung"]', 'Berufsmusikerinnen und Berufsmusiker,  Ausbildung. Die BerufsmusikerInnen müssen SMV-Mitglied sein. Bei Ensembles muss mindestens die Hälfte der MusikerInnen Mitglied des SMV sein. Ausländische Studierende müssen seit mindestens fünf Jahren in der Schweiz wohnhaft sein.', 'Privatpersonen, Institutionen', 'Ende Februar, Mai, August, November', 'Schweiz. Stiftung für die Förderung und Unterstützung von Berufsmusiker/innen, c/o SMV, Kasernenstrasse 15, 8004 Zürich', 'Ausbildungsbestätigung, Kontoangaben, Referenzen, detaillierte Beschreibung des Projektes, detailliertes Budget, Ausbildungs-/Berufsdiplome, Kursunterlagen, Steuerausweis Gesuchsteller/in und Eltern. Gesuchsunterlagen sind in 4-facher Ausführung einzureichen. Behandlungstermine: Ende Februar, Mai, August', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen, detaillierte Beschreibung des Projektes, detailliertes Budget, Ausbildungs-/Berufsdiplome, Kursunterlagen, Steuerausweis Gesuchsteller/in und Eltern. Gesuchsunterlagen sind in 4-facher Ausführung einzureichen. Behandlungstermine: Ende Februar, Mai, August", "ZIELGRUPPE": "Berufsmusikerinnen und Berufsmusiker,  Ausbildung. Die BerufsmusikerInnen müssen SMV-Mitglied sein. Bei Ensembles muss mindestens die Hälfte der MusikerInnen Mitglied des SMV sein. Ausländische Studierende müssen seit mindestens fünf Jahren in der Schweiz wohnhaft sein.", "EMPFANGSSTELLE": "Schweiz. Stiftung für die Förderung und Unterstützung von Berufsmusiker/innen, c/o SMV, Kasernenstrasse 15, 8004 Zürich", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ende Februar, Mai, August, November"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (110, 'schweiz-stiftung-fur-blindentechn-hilfsmittel', 'Schweiz. Stiftung für blindentechn. Hilfsmittel', 71, 'Die Stiftung bezweckt die vergünstigte Abgabe von blindentechnischen Hilfsmitteln in Härtefällen an Einzelpersonen. Sie unterstützt die Förderung der Entwicklung blindentechnischer Hilfsmittel.', 'c/o Daniel Fernandez, obvita Sehberatung, Schützengasse 4, 9000 St. Gallen, 071 246 61 10 (obvita Sehberatung, Daniel Fernandez), daniel.fernandez@obvita.ch', 'c/o Daniel Fernandez, obvita Sehberatung, Schützengasse 4, 9000 St. Gallen, (obvita Sehberatung, Daniel Fernandez)', '9000', 'St. Gallen', '["071 246 61 10"]', '["daniel.fernandez@obvita.ch"]', '["obvita.ch"]', 'Blinde und Menschen mit Sehinderungen', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', 'Schweiz. Stiftung für blindentechnische Hilfsmittel, c/o Daniel Fernandez, obvita Sehberatung, Schützengasse 4, 9000 St. Gallen / daniel.fernandez@obvita.ch', 'Kontoangaben. Das Gesuchformular kann per Mail bei daniel.fernandez@obvita.ch angefordert werden.', '{"BEILAGEN": "Kontoangaben. Das Gesuchformular kann per Mail bei daniel.fernandez@obvita.ch angefordert werden.", "ZIELGRUPPE": "Blinde und Menschen mit Sehinderungen", "EMPFANGSSTELLE": "Schweiz. Stiftung für blindentechnische Hilfsmittel, c/o Daniel Fernandez, obvita Sehberatung, Schützengasse 4, 9000 St. Gallen / daniel.fernandez@obvita.ch", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (111, 'schweiz-stiftung-fur-das-cerebral-gelahmte-kind', 'Schweiz. Stiftung für das cerebral gelähmte Kind', 72, 'Ziel ist die Früherfassung, Förderung, Ausbildung, Pflege und soziale Betreuung von Menschen mit cerebralen Bewegungsstörungen, spina bifida oder Muskeldystrophie mit Wohnsitz in der Schweiz. Ergriffen oder unterstützt werden alle Massnahmen, welche nach dem jeweiligen Stand der Wissenschaft zur Erreichung dieser Ziele angezeigt erscheinen.', 'Erlachstrasse 14, Postfach, 3001 Bern, 031 308 15 15, cerebral@cerebral.ch, www.cerebral.ch', 'Erlachstrasse 14, Postfach, 3001 Bern,, www.', '3001', 'Bern', '["031 308 15 15"]', '["cerebral@cerebral.ch"]', '["cerebral.ch", "www.cerebral.ch"]', 'Menschen mit cerebralen Bewegungsstörungen, spina bifida oder Muskeldystrophie', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Menschen mit cerebralen Bewegungsstörungen, spina bifida oder Muskeldystrophie", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (112, 'schweiz-stiftung-fur-die-hilfe-an-straffalligen', 'Schweiz. Stiftung für die Hilfe an Straffälligen', 73, 'Die Stiftung finanziert die Sanierung der Gesamtschulden von Straffälligen mit zinslosen, rückzahlbaren Darlehen, ausnahmsweise auch durch nicht rückzahlbare Unterstützungsleistungen. Die Sanierungen selbst werden durch die kantonalen Bewährungshilfen oder andere geeignete Stellen vorbereitet und begleitet.', 'Fondation suisse pour l''aide aux condamnés et à leurs familles, 3000 Bern, info@hilfeanstraffaellige.ch, www.hilfeanstraffaellige.ch', 'Fondation suisse pour l''aide aux condamnés et à leurs familles, 3000 Bern, www.', '3000', 'Bern', '[]', '["info@hilfeanstraffaellige.ch"]', '["hilfeanstraffaellige.ch", "www.hilfeanstraffaellige.ch"]', 'Straffällige', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', NULL, NULL, '{"ZIELGRUPPE": "Straffällige", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (113, 'schweiz-stiftung-fur-kinder-und-jugendliche-in-not', 'Schweiz. Stiftung für Kinder und Jugendliche in Not', 73, 'Unterstützung von Kindern und Jugendlichen in Not mit einer einmaligen Spende.', 'Seeburgstrasse 18, 6006 Luzern, 041 370 13 45, info@kinder-stiftung.ch, www.kinder-stiftung.ch', 'Seeburgstrasse 18, 6006 Luzern,, www.', '6006', 'Luzern', '["041 370 13 45"]', '["info@kinder-stiftung.ch"]', '["kinder-stiftung.ch", "www.kinder-stiftung.ch"]', 'Kinder und Jugendliche bis 18 Jahre', 'Privatpersonen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Antragsformular, Kostenvoranschlag, Budget, finanzielle Situation (steht auf dem Formular)', '{"BEILAGEN": "Antragsformular, Kostenvoranschlag, Budget, finanzielle Situation (steht auf dem Formular)", "ZIELGRUPPE": "Kinder und Jugendliche bis 18 Jahre", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (121, 'spendenparlament-zurich', 'Spendenparlament Zürich', 76, 'Das Spendenparlament besteht aus persönlichen und institutionellen Mitgliedern, die Fr. 500.- resp Fr. 2500.- pro Jahr bezahlen (Jungmitglieder bis 30 Jahre 150.-, Paare Fr. 750.-). An zwei Parlamentssitzungen pro Jahr entscheiden die Mitglieder, wie das Geld verteilt wird. Es können Projekte im sozialen und kulturellen Bereich mit hohem Integrationscharakter eingereicht werden. Eine Fachkommission prüft die Projekte auf ihre Effektivität und Seriosität.', 'Baslerstrasse 30, 8048 Zürich, info@spendenparlament.ch, www.spendenparlament.ch', 'Baslerstrasse 30, 8048 Zürich, www.', '8048', 'Zürich', '[]', '["info@spendenparlament.ch"]', '["spendenparlament.ch", "www.spendenparlament.ch"]', 'Kleine, mittlere Institutionen im sozialen und kulturellen Bereich, eventuell auch Teilprojekte von grösseren Institutionen.', 'Institutionen', 'Ganzes Jahr', 'info@spendenparlament.ch', 'Gesuchsformulare siehe Website', '{"BEILAGEN": "Gesuchsformulare siehe Website", "ZIELGRUPPE": "Kleine, mittlere Institutionen im sozialen und kulturellen Bereich, eventuell auch Teilprojekte von grösseren Institutionen.", "EMPFANGSSTELLE": "info@spendenparlament.ch", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (114, 'schweiz-studienstift-fonds-f-begabte-j-menschen', 'Schweiz. Studienstift. – Fonds f. begabte j. Menschen', 73, 'Die Schweizerische Studienstiftung fördert an Schweizer Hoch- und Fachhochschulen leistungsstarke, breit interessierte Studierende, deren Persönlichkeit, Kreativität und intellektuelle Fähigkeiten besondere Leistungen in Wissenschaft, Wirtschaft, Kultur und Politik erwarten lassen. Ihr Ziel ist es, junge Menschen zu unterstützen, die in unserer Gesellschaft Verantwortung übernehmen können und wollen. Sie bietet den in ihr Förderprogramm aufgenommenen Studierenden und Doktorierenden studienergänzende, interdisziplinäre Bildungsangebote, finanzielle Unterstützung, individuelle Betreuung und Beratung sowie vielfältige Vernetzungsmöglichkeiten.', '8032 Zürich, 044 233 33 00, info@studienstiftung.ch, www.studienstiftung.ch', '8032 Zürich,, www.', '8032', 'Zürich', '["044 233 33 00"]', '["info@studienstiftung.ch"]', '["studienstiftung.ch", "www.studienstiftung.ch"]', 'Studierende an Schweizer Hoch- und Fachhochschulen mit Wohnsitz in der Schweiz (Schweizer Staatsbürgerschaft ist nicht notwendig). 
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (115, 'schweiz-verband-alleinerziehender-mutter-und-vater', 'Schweiz. Verband alleinerziehender Mütter und Väter', 74, 'Anlauf- und Auskunftsstelle für alle Belange, die Alleinerziehende und ihre Kinder betreffen.
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (116, 'sekretariat-stiftung-fur-die-adliswiler-jugend', 'Sekretariat Stiftung für die Adliswiler Jugend', 75, 'Beiträge werden ausgerichtet an junge Adliswilerinnen und Adliswiler  für Aus- und Weiterbildungen im In- und Ausland,  für künstlerische, handwerkliche, sportliche, gesellschaftliche oder andere kreative Projekte, sowie auch bei persönlichen Notlagen, die von der öffentlichen Sozialhilfe nicht abgedeckt werden können.', 'Stiftung für die Adliswiler Jugend, c/o Stadt Adliswil, Soziale Aufgaben, Zürichstrasse 10, Postfach, saj@adliswil.ch', 'Stiftung für die Adliswiler Jugend, c/o Stadt Adliswil, Soziale Aufgaben, Zürichstrasse 10, Postfach', NULL, NULL, '[]', '["saj@adliswil.ch"]', '["adliswil.ch"]', 'Jugend & Familie, Ausbildung, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Personalien unter Beilage des Lebenslaufes, der ausführlich über Ausbildung, Beruf und andere Tätigkeiten Auskunft zu geben hat. Aufsatz (ca. eine A4-Seite), der das Ziel, das erreicht werden soll, beschreibt und über die berufliche sowie private Zukunft Auskunft gibt. Sofern der Beitrag als Folge einer Notlage angefordert wird, ist diese im Detail zu beschreiben.', '{"BEILAGEN": "Personalien unter Beilage des Lebenslaufes, der ausführlich über Ausbildung, Beruf und andere Tätigkeiten Auskunft zu geben hat. Aufsatz (ca. eine A4-Seite), der das Ziel, das erreicht werden soll, beschreibt und über die berufliche sowie private Zukunft Auskunft gibt. Sofern der Beitrag als Folge einer Notlage angefordert wird, ist diese im Detail zu beschreiben.", "ZIELGRUPPE": "Jugend & Familie, Ausbildung, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (117, 'shelter-stiftung', 'Shelter Stiftung', 75, 'Materielle und ideelle Unterstützung von Frauen, die ohne eigenes Verschulden ihr Leben mit Zwangsprostitution fristen müssen. Tätigkeitsschwerpunkt Europa.', 'c/o Mathys Schmid Partner, Rittergasse 12, 4051 Basel, 061 270 99 00, dominik.schniepper@msp-law.ch', 'c/o Mathys Schmid Partner, Rittergasse 12, 4051 Basel', '4051', 'Basel', '["061 270 99 00"]', '["dominik.schniepper@msp-law.ch"]', '["msp-law.ch"]', 'Jugend, Familie, Frauen, Ausländerinnen, Soziale Institutionen', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend, Familie, Frauen, Ausländerinnen, Soziale Institutionen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (118, 'solidaritatsfond-fur-mutter-und-kind-sofo', 'Solidaritätsfond für Mutter und Kind SOFO', 75, 'Der SOFO gewährt finanzielle Hilfe an Frauen/Familien, die wegen Schwangerschaft, Geburt oder Kleinkinderbetreuung (bis sechsjährig)  in Not geraten, unabhängig von deren Zivilstand, Konfession oder Staatszugehörigkeit. Die Beiträge werden im Sinne einer Überbrückungshilfe geleistet und sind in der Regel einmalig. Keine Beratungen.', 'Schweiz. Kath. Frauenbund, Kasernenplatz 1, Postfach 7854, 6000 Luzern, 041 226 02 27, sofo@frauenbund.ch, www.frauenbund.ch', 'Schweiz. Kath. Frauenbund, Kasernenplatz 1, Postfach 7854, 6000 Luzern,, www.', '6000', 'Luzern', '["041 226 02 27"]', '["sofo@frauenbund.ch"]', '["frauenbund.ch", "www.frauenbund.ch"]', 'Frauen mit Kleinkindern, Alleinerziehende, Familien', 'Privatpersonen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Frauen mit Kleinkindern, Alleinerziehende, Familien", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (119, 'sophie-und-karl-binding-stiftung', 'Sophie und Karl Binding Stiftung', 76, 'Die Sophie und Karl Binding Stiftung ist eine gemeinnützige Förderstiftung und ist politisch und religiös unabhängig. Sie fördert Projekte in den Bereichen Umwelt, Soziales, Bildung und Kultur in der ganzen Schweiz. Im Förderbereich «Soziales» unterstützt die Stiftung Arbeitsintegrationsprojekte für Jugendliche mit Migrationshintergrund. Für weitere Details konsultieren Sie bitte die Website, Bereich «Gesuche an uns». Nur Gesuche, die den auf der Website veröffentlichten Vorgaben entsprechen, werden behandelt.', 'Rennweg 50, 4020 Basel, 061 317 12 39, contact@binding-stiftung.ch, www.binding-stiftung.ch', 'Rennweg 50, 4020 Basel,, www.', '4020', 'Basel', '["061 317 12 39"]', '["contact@binding-stiftung.ch"]', '["binding-stiftung.ch", "www.binding-stiftung.ch"]', 'Jugendliche mit Migrationshintergrund, ohne Lehrstelle. Keine Einzelpersonen, nur Organisationen.', 'Institutionen', 'Ganzes Jahr. 4-mal jährlich, siehe Website. Spezialformular anfordern', NULL, 'Referenzen, weitere Beilagen siehe Website', '{"BEILAGEN": "Referenzen, weitere Beilagen siehe Website", "ZIELGRUPPE": "Jugendliche mit Migrationshintergrund, ohne Lehrstelle. Keine Einzelpersonen, nur Organisationen.", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. 4-mal jährlich, siehe Website. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
