INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (128, 'stiftung-denk-an-mich', 'Stiftung Denk an mich', 79, 'Die Stiftung Denk an mich unterstützt Ferien und Freizeitaktivitäten von Menschen mit Behinderungen. Als Solidaritätsstiftung des Schweizer Radio und Fernsehens SRF setzt sie sich seit über 50 Jahren für die gleichberechtigte Teilhabe von Kindern, Jugendlichen und Erwachsenen mit Behinderungen am gesellschaftlichen Leben ein. Dazu gehören auch Ferien und Freizeitaktivitäten, die sich viele Menschen mit Behinderungen nicht leisten können. Die Stiftung Denk an mich schliesst diese Lücke, unterstützt finanziell und schafft so ein Stück Lebensqualität für Betroffene und deren Angehörigen.', 'Stiftung Denk an mich, Schweizer Radio und Fernsehen, Fernsehstrasse 1-4, Postfach, 8052 Zürich', 'Stiftung Denk an mich, Schweizer Radio und Fernsehen, Fernsehstrasse 1-4, Postfach, 8052 Zürich', '8052', 'Zürich', '[]', '[]', '[]', 'Menschen mit Behinderungen', 'Privatpersonen, Institutionen', '6 Wochen (Einzelpersonen) / 10 Wochen (Gruppen) vor Beginn der Aktivität', 'www.denkanmich.ch/gesuch-einreichen', 'Details (wann und wo findet die Aktivität statt?), Budget der geplanten Aktivität, schriftliche Bestätigung IV/EL-Leistungen/Sozialhilfe und Kopie der letzten Steuererklärung.', '{"BEILAGEN": "Details (wann und wo findet die Aktivität statt?), Budget der geplanten Aktivität, schriftliche Bestätigung IV/EL-Leistungen/Sozialhilfe und Kopie der letzten Steuererklärung.", "ZIELGRUPPE": "Menschen mit Behinderungen", "EMPFANGSSTELLE": "www.denkanmich.ch/gesuch-einreichen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "6 Wochen (Einzelpersonen) / 10 Wochen (Gruppen) vor Beginn der Aktivität"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
