INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (135, 'stiftung-erna-und-curt-burgauer', 'Stiftung Erna und Curt Burgauer', 82, 'Jungen Musikerinnen/Musikern kann ein Studium durch Beiträge erleichtert werden. Der Ankauf eines Instrumentes kann unterstützt werden. Beiträge an förderungswürdige junge Künstler/innen für Ausstellungen und  Katalogprojekte. Nur einzelne Künstler/innen, keine Gruppenproduktionen.', 'c/o Zürcher Kunstgesellschaft, Winkelwiese 4, 8001 Zürich, 044 253 84 84 (Empfang), burgauer.stiftung@kunsthaus.ch, www.burgauerstiftung.org', 'c/o Zürcher Kunstgesellschaft, Winkelwiese 4, 8001 Zürich, (Empfang)', '8001', 'Zürich', '["044 253 84 84"]', '["burgauer.stiftung@kunsthaus.ch"]', '["kunsthaus.ch", "www.burgauerstiftung.org"]', 'Bildende Kunst, Musik', 'Privatpersonen', 'Ganzes Jahr - mit Dossier per Post', NULL, 'Ausbildungsbestätigung, Projektbeschrieb/Umstände, Lebenslauf, Ausbildungsbestätigung, Budget, ev. Aufenthaltsbewilligung', '{"BEILAGEN": "Ausbildungsbestätigung, Projektbeschrieb/Umstände, Lebenslauf, Ausbildungsbestätigung, Budget, ev. Aufenthaltsbewilligung", "ZIELGRUPPE": "Bildende Kunst, Musik", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr - mit Dossier per Post"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (136, 'stiftung-familienwohnungen', 'Stiftung Familienwohnungen', 91, 'Vermietung von preisgünstigen Wohnungen und Einfamilienhäusern an kinderreiche Familien mit mindestens drei Kindern und mit zweijährigem Wohnsitz in der Stadt Zürich. Bewerberfamilien müssen die Vermietungsvorschriften für städtisch subventionierte Wohnungen erfüllen. Es besteht eine lange Warteliste.', 'Stadt Zürich, Feldeggstrasse 60, 8008 Zürich, 044 412 33 18 , sfw-info@zuerich.ch', 'Stadt Zürich, Feldeggstrasse 60, 8008 Zürich', '8008', 'Zürich', '["044 412 33 18"]', '["sfw-info@zuerich.ch"]', '["zuerich.ch"]', 'Jugend & Familie', 'Privatpersonen', 'Ganzes Jahr. Spezialformular anfordern', NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (137, 'stiftung-frei-bett-tieche', 'Stiftung Frei-Bett Tièche', 82, 'Die Stiftung gewährt Beiträge an sämtliche mit einem Spitalaufenthalt im Stadtspital Waid Zürich in Zusammenhang stehende Kosten, insbesondere auch an Transport-, Kur- und Eingliederungskosten sowie an die Auslagen ambulanter Patientinnen/Patienten für therapeutische und diagnostische Massnahmen. Empfänger/innen sind arme, kranke, schutzlose, spitalbedürftige Patientinnen/Patienten ohne Rücksicht auf Nationalität, Bürgerort, Wohnsitz, Konfession und Alter, sofern kein Rechtsanspruch gegenüber Dritten besteht.', 'c/o Gesundheits- und Umweltdepartement der Stadt Zürich, Walchestrasse 31 - 33, 8006 Zürich', 'c/o Gesundheits- und Umweltdepartement der Stadt Zürich, Walchestrasse 31 - 33, 8006 Zürich', '8006', 'Zürich', '[]', '[]', '[]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Arztzeugnis, Kontoangaben, dokumentierte Begründung der Hilfsbedürftigkeit', '{"BEILAGEN": "Arztzeugnis, Kontoangaben, dokumentierte Begründung der Hilfsbedürftigkeit", "ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (138, 'stiftung-friedbrunnen-und-holderbach', 'Stiftung Friedbrunnen und Holderbach', 82, 'Die Stiftung vermietet preisgünstige Wohnungen für Jugendliche, Studentinnen/Studenten und Familien und ältere Personen mit bescheidenem Einkommen im Sinne von Art. 80 ff. des Zivilgesetzbuches. Anfragen zu freien Wohnungen sind zu richten an Hauseigentümerverband Zürich 044 487 17 57. Siedlung Holderbach, ZH-Affoltern - Wohnungen für Familien mit bescheidenem Einkommen und für Jugendliche in Ausbildung. Siedlung Friedbrunnen, ZH-Albisrieden - Wohnungen für ältere, noch selbständige Personen mit bescheidenem Einkommen.', 'Lindenhof 2-4, 8001 Zürich, 044 687 24 25 (Privat - Finanzvorstand), 076 337 19 34 (Privat - Präsident), stiftung.fb&hb@bluewin.ch', 'Lindenhof 2-4, 8001 Zürich, (Privat - Finanzvorstand), (Privat - Präsident), stiftung.fb&', '8001', 'Zürich', '["044 687 24 25", "076 337 19 34"]', '["hb@bluewin.ch"]', '["bluewin.ch"]', 'Jugend und Familie, Verwendungszweck: Ausbildung, Verschiedenes', 'Privatpersonen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Ausbildungsbestätigung, Kontoangaben, Referenzen, Steuerrechnung', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen, Steuerrechnung", "ZIELGRUPPE": "Jugend und Familie, Verwendungszweck: Ausbildung, Verschiedenes", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (139, 'stiftung-fur-das-lungengesundheit-krankheit-kind', 'Stiftung für das lungenGesundheit/Krankheit Kind', 83, 'Ergreifung und Förderung aller Massnahmen im Interesse von Kindern, Jugendlichen und jungen Erwachsenen mit chronischen Lungenkrankheiten, insbesondere Cystischer Pankreasfibrose und Asthma, sowie im Interesse der Familien dieser Kinder; kann auch andere Massnahmen ergreifen oder unterstützen, welche auf gemeinnütziger Basis ähnliche Zwecke verfolgen.', 'Lerchenberg 37, 8046 Zürich, 044 371 64 40, info@stiftung-luki.ch, www.stiftung-luki.ch', 'Lerchenberg 37, 8046 Zürich,, www.', '8046', 'Zürich', '["044 371 64 40"]', '["info@stiftung-luki.ch"]', '["stiftung-luki.ch", "www.stiftung-luki.ch"]', 'Die Stiftung ist hauptsächlich im Kanton Zürich tätig, im Umfeld des Kinderspitals Zürich und des Universitätsspitals Zürich sowie den Einzugsgebieten des Kantonspitals 
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (140, 'stiftung-fur-erforschung-der-frauenarbeit', 'Stiftung für Erforschung der Frauenarbeit', 83, 'Die Stiftung erforscht Frauenarbeit, fördert und initiiert Projekte und Massnahmen zur Gleichstellung von Frauen in Bildung und Arbeitswelt.', 'Rita Schmid Göldi, Präsidentin, Rotachstrasse 22, 8003 Zürich, info@stiftung-frauenarbeit.ch, www.stiftung-frauenarbeit.ch', 'Rita Schmid Göldi, Präsidentin, Rotachstrasse 22, 8003 Zürich, www.', '8003', 'Zürich', '[]', '["info@stiftung-frauenarbeit.ch"]', '["stiftung-frauenarbeit.ch", "www.stiftung-frauenarbeit.ch"]', 'Projekte/Massnahmen Gleichstellung von Frauen', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Projektbeschreibung, finanzielle Mittel', '{"BEILAGEN": "Projektbeschreibung, finanzielle Mittel", "ZIELGRUPPE": "Projekte/Massnahmen Gleichstellung von Frauen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (142, 'stiftung-fur-kinder-in-der-schweiz', 'Stiftung für Kinder in der Schweiz', 84, 'Die Stiftung für Kinder in der Schweiz unterstützt und fördert benachteiligte Kinder in der Schweiz. Dabei stellen wir immer die Kinder und ihre Bedürfnisse in den Mittelpunkt, unabhängig von Kultur, Ängsten, sozialem Hintergrund - denn alle Kinder in unserer Gesellschaft sind gleichwertig und haben das Recht auf Befriedigung ihrer Grundbedürfnisse, Bildung und Respektierung ihrer Individualität.', 'Seestrasse 61, Postfach 242, 6052 Hergiswil NW, 041 632 44 74, mail@kinderstiftung.info, www.kinderstiftung.info', 'Seestrasse 61, Postfach 242, 6052 Hergiswil NW,, www.', '6052', 'Hergiswil NW', '["041 632 44 74"]', '["mail@kinderstiftung.info"]', '["kinderstiftung.info", "www.kinderstiftung.info"]', 'Kinder und Jugendliche bis 18 Jahre, die in der Schweiz wohnhaft und in sozialer Not sind', 'Privatpersonen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, Referenzen, Kopie Steuerveranlagung, Bestätigung über Erhalt Ergänzungsleistungen (Leistung / Kosten)', '{"BEILAGEN": "Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, Referenzen, Kopie Steuerveranlagung, Bestätigung über Erhalt Ergänzungsleistungen (Leistung / Kosten)", "ZIELGRUPPE": "Kinder und Jugendliche bis 18 Jahre, die in der Schweiz wohnhaft und in sozialer Not sind", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (143, 'stiftung-fur-pflegebedurftige', 'Stiftung für Pflegebedürftige', 84, 'Unterstützung gemeinnütziger Institutionen, von Krankenhäusern, Kliniken und Pflegeheimen. Unterstützung wissenschaftlicher Forschungen im Gesundheitswesen.', 'c/o PD Services AG, Mühlebachstrasse 6, 8008 Zürich, 044 919 04 07', 'c/o PD Services AG, Mühlebachstrasse 6, 8008 Zürich', '8008', 'Zürich', '["044 919 04 07"]', '[]', '[]', 'Menschen mit Behinderungen, Krankheit', 'Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Menschen mit Behinderungen, Krankheit", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
