INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (147, 'stiftung-hilfe-fur-kinder', 'Stiftung Hilfe für Kinder', 85, 'Die Stiftung Hilfe für Kinder bezweckt die Unterstützung von notleidenden Kindern durch Hilfeleistungen bei Notlagen in körperlicher, psychischer und materieller Hinsicht.', 'Bachstrasse 11a, 8902 Urdorf, 044  242 37 37, kontakt@stiftung-hfk.ch, www.stiftung-hfk.ch', 'Bachstrasse 11a, 8902 Urdorf, 044 242 37 37, www.', '8902', 'Urdorf', '[]', '["kontakt@stiftung-hfk.ch"]', '["stiftung-hfk.ch", "www.stiftung-hfk.ch"]', 'Betagte Menschen in Not', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Keine Beschränkung. Spezialformular anfordern', 'Stiftung Hilfe für Kinder, Bachstrasse 11a, 8902 Urdorf', 'Budget, Antragsformular, Offerte, Kostenvoranschlag', '{"BEILAGEN": "Budget, Antragsformular, Offerte, Kostenvoranschlag", "ZIELGRUPPE": "Betagte Menschen in Not", "EMPFANGSSTELLE": "Stiftung Hilfe für Kinder, Bachstrasse 11a, 8902 Urdorf", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Keine Beschränkung. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (148, 'stiftung-hulfsgesellschaft-winterthur', 'Stiftung «Hülfsgesellschaft Winterthur»', 86, 'Wirkt als gemeinnützige Institution durch Einsatz ihrer Mittel und Möglichkeiten wohltätig in der Region Winterthur. Führt eigene soziale Einrichtungen (Seniorenzentrum Wiesengrund und Wohnheim Sonnenberg), gewährt gezielt Zuwendungen an Privatpersonen zur Linderung materieller Not oder zur Förderung ihrer Ausbildung und richtet Beiträge aus an gemeinnützige Organisationen und Institutionen, die schwergewichtig in den Bereichen der Sozialhilfe, der Jugend- und Altersarbeit, der Bildung, der Betreuung und des Gesundheitswesens tätig sind. 
