INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (150, 'stiftung-kinderhilfe-sternschnuppe', 'Stiftung Kinderhilfe Sternschnuppe', 87, 'Unser Stiftungszweck ist es, Freude und Abwechslung in das Leben von Kindern und Jugendlichen bis 18 Jahre zu bringen, die mit einer Krankheit, einer Behinderung oder mit den Folgen einer schweren Verletzung leben. Wir erfüllen Herzenswünsche von Kindern und Jugendlichen, finanzieren Sternenprojekte für Spitäler, Heime oder ähnliche Institutionen, die sich für die Interessen von betroffenen Kindern und Jugendlichen einsetzen und offerieren «Freizeitsterne», vergnügliche Freizeiterlebnisse für betroffene Kinder und ihre ganze Familie.', 'Weinbergstrasse 131, 8006 Zürich, 044 368 30 40, stern@sternschnuppe.ch, www.sternschnuppe.ch', 'Weinbergstrasse 131, 8006 Zürich,, www.', '8006', 'Zürich', '["044 368 30 40"]', '["stern@sternschnuppe.ch"]', '["sternschnuppe.ch", "www.sternschnuppe.ch"]', 'Kinder, Jugendliche, Familie, Menschen mit Behinderungen, Kranke, Armut. Es können nur Kinder berücksichtigt werden, die in der Schweiz leben oder über längere Zeit hier behandelt werden.', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Kinder, Jugendliche, Familie, Menschen mit Behinderungen, Kranke, Armut. Es können nur Kinder berücksichtigt werden, die in der Schweiz leben oder über längere Zeit hier behandelt werden.", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (151, 'stiftung-licht-fur-vergessene-kinder', 'Stiftung Licht für vergessene Kinder', 87, 'Die Stiftung bezweckt die Unterstützung von Waisenkindern und von verlassenen oder in Not geratenen Kindern im In- und Ausland.', 'Dorfstrasse 15A, 6300 Zug, kontakt@Lfvk.ch, www.lfvk.ch', 'Dorfstrasse 15A, 6300 Zug', '6300', 'Zug', '[]', '["kontakt@Lfvk.ch"]', '["Lfvk.ch", "www.lfvk.ch"]', NULL, 'Privatpersonen, Institutionen', NULL, NULL, NULL, '{"GESUCHSTELLENDE": "Privatpersonen, Institutionen"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (152, 'stiftung-nak-humanitas', 'Stiftung NAK-Humanitas', 87, 'Die Stiftung NAK-Humanitas fördert und initiiert gemeinnützige und soziale Projekte im In- und Ausland. Sie unterstützt humanitäre Projekte in kriegs- und katastrophengeschädigten Gebieten weltweit. Sie bevorzugt kleinere Institutionen mit regionalem Bezug. Sie fokussiert ihre Tätigkeit auf die Bereiche Krankheit und Alter, Soziales und humanitäre Hilfe.', 'Ueberlandstrasse 243, 8051 Zürich, 043 268 38 38, info@nak-humanitas.ch, www.nak-humanitas.ch', 'Ueberlandstrasse 243, 8051 Zürich,, www.', '8051', 'Zürich', '["043 268 38 38"]', '["info@nak-humanitas.ch"]', '["nak-humanitas.ch", "www.nak-humanitas.ch"]', 'Soziale, gemeinnützige und humanitäre Institutionen und Organisationen in der Schweiz und im Ausland', 'Institutionen', 'Ganzes Jahr. Spezialformular anfordern', 'Per Mail: info@nak-humanitas.ch', 'Kontoangaben, Referenzen, gemäss Angaben auf der Webseite', '{"BEILAGEN": "Kontoangaben, Referenzen, gemäss Angaben auf der Webseite", "ZIELGRUPPE": "Soziale, gemeinnützige und humanitäre Institutionen und Organisationen in der Schweiz und im Ausland", "EMPFANGSSTELLE": "Per Mail: info@nak-humanitas.ch", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (153, 'stiftung-pro-aegrotis', 'Stiftung Pro Aegrotis', 88, 'Zweck der Stiftung: Unterstützung bedürftiger Kranker. Grundsätzlich können Beiträge an Personen ausgerichtet werden, die zur Behandlung einer Krankheit, Behebung von Unfallfolgen, Verbesserung ihres Gesundheitszustandes oder für die Pflege zu Hause am Lebensende fremder finanzieller Hilfe bedürfen. Die Tä-tigkeit der Stiftung erstreckt sich auf das ganze Gebiet der Schweiz. Gesuche können eingereicht werden für bedürftige Menschen – auch in der Schweiz lebende Ausländer/in- nen – jeden Alters, jeden Standes und jeder Konfession . Es werden nur Gesuche von offiziellen Institutionen entgegengenommen.', 'c/o Christina Domke · Franz Lang-Weg 10 · 4500 Solothurn · Tel. 032 621 44 15 pro-aegrotis@bluewin.ch, www.pro-aegrotis.ch', 'c/o Christina Domke · Franz Lang-Weg 10 · 4500 Solothurn · Tel.', '4500', 'Solothurn · Tel. 032 621 44 15 pro-aegrotis@bluewin.ch', '["032 621 44 15"]', '["pro-aegrotis@bluewin.ch"]', '["bluewin.ch", "www.pro-aegrotis.ch"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Budget, Begleitschreiben, Belege der zu finanzierenden Kosten, Einzahlungsschein', '{"BEILAGEN": "Budget, Begleitschreiben, Belege der zu finanzierenden Kosten, Einzahlungsschein", "ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (154, 'stiftung-schwiizer-halfed-schwiizer', 'Stiftung Schwiizer hälfed Schwiizer', 88, 'Die Stiftung bezweckt die Förderung der Solidarität mit Schweizerinnen und Schweizern sowie Niedergelassene (Ausweis C), die unverschuldet in eine finanzielle Notlage geraten sind.', 'Clausiusstrasse 45, 8006 Zürich, 044 269 40 57, info@stiftung-shs.ch, www.stiftung-shs.ch', 'Clausiusstrasse 45, 8006 Zürich,, www.', '8006', 'Zürich', '["044 269 40 57"]', '["info@stiftung-shs.ch"]', '["stiftung-shs.ch", "www.stiftung-shs.ch"]', 'Einzelpersonen, Familien', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', 'Gesuche können direkt durch private Personen eingereicht werden. Wenn die Sozialbehörde involviert ist muss das Gesuch durch die Behörde eingereicht werden.
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (155, 'stiftung-solidaritat-mit-sehgeschadigten', 'Stiftung Solidarität mit Sehgeschädigten', 89, 'Die Stiftung unterstützt Organisationen in Projekten für blinde und sehMenschen mit Behinderungen Personen in der Schweiz. Sie leistet Hilfe zur Selbsthilfe. Ihr Ziel ist die Förderung der Eigenständigkeit.
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (156, 'stiftung-solidaritatsfonds-fur-ausl-studierende', 'Stiftung Solidaritätsfonds für ausl. Studierende', 89, 'Stipendierung von ausländischen Studierenden, welche regulär an der UZH oder ETH Zürich immatrikuliert sind. Bedingungen gemäss Stipendienreglement (www.education.uzh.ch/de/kommissionen/solidaritaetsfonds.html).
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (157, 'stiftung-sos-beobachter', 'Stiftung SOS Beobachter', 90, 'Zweck der Stiftung ist die Leistung von Individualhilfe an natürliche oder juristische Personen, wohnhaft in der Schweiz, die aus sozialen oder anderen Gründen als unterstützungswürdig erscheinen.', 'Flurstrasse 55, Postfach, 8021 Zürich 1, 058 269 21 21, sosbeobachter@sos.beobachter.ch, www.sosbeobachter.ch', 'Flurstrasse 55, Postfach, 8021 Zürich 1', '8021', 'Zürich 1', '["058 269 21 21"]', '["sosbeobachter@sos.beobachter.ch"]', '["sos.beobachter.ch", "www.sosbeobachter.ch"]', 'Armutsbetroffene, Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen, Ausbildung, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, Referenzen, Übersicht Lebenshaltungskosten, Einkommens-, Vermögenslage, Finanzierungsplan', '{"BEILAGEN": "Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, Referenzen, Übersicht Lebenshaltungskosten, Einkommens-, Vermögenslage, Finanzierungsplan", "ZIELGRUPPE": "Armutsbetroffene, Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen, Ausbildung, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (158, 'stiftung-stiefel-zangger', 'Stiftung  Stiefel-Zangger', 90, 'Förderung der weiteren Ausbildung des akademischen Nachwuchses der Universität Zürich durch die Vergabe von Stipendien.', 'Universität Zürich, Hirschengraben 48, UZH Grants Office, 8001 Zürich, 044 634 20 30, support@research.uzh.ch', 'Universität Zürich, Hirschengraben 48, UZH Grants Office, 8001 Zürich', '8001', 'Zürich', '["044 634 20 30"]', '["support@research.uzh.ch"]', '["research.uzh.ch"]', 'Nachwuchsforschende der Universität Zürich', 'Privatpersonen', 'Die Stipendienvergabe erfolgt im Rahmen des Evaluationsprozesse von Gesuchen um Mobilitätsstipendien am 1.3. und 1.9. des Jahres', NULL, NULL, '{"ZIELGRUPPE": "Nachwuchsforschende der Universität Zürich", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Die Stipendienvergabe erfolgt im Rahmen des Evaluationsprozesse von Gesuchen um Mobilitätsstipendien am 1.3. und 1.9. des Jahres"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (159, 'stiftung-uitikon', 'Stiftung Uitikon', 90, 'Die Stiftung Uitikon bezweckt die Förderung und Unterstützung von Projekten, Institutionen, Aktivitäten und Hilfeleistungen zugunsten von  hilfs- und unterstützungsbedürftigen Personen der Gemeinde Uitikon.', 'c/o Gemeinderatskanzlei Uitikon, Zürcherstrasse 59, 8142 Uitikon Waldegg, 044 200 15 00, 044 200 15 19, sinisa.kostic@uitikon.org, www.uitikon.ch', 'c/o Gemeinderatskanzlei Uitikon, Zürcherstrasse 59, 8142 Uitikon Waldegg', '8142', 'Uitikon Waldegg', '["044 200 15 00", "044 200 15 19"]', '["sinisa.kostic@uitikon.org"]', '["uitikon.org", "www.uitikon.ch"]', 'Einwohnerinnen und Einwohnern, Bürgerinnen und Bürger von Uitikon und Personen, die in einer besonderen Beziehung zur Gemeinde stehen', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, alles zur Prüfung eines Gesuches Erforderliche', '{"BEILAGEN": "Arztzeugnis, Ausbildungsbestätigung, Kontoangaben, alles zur Prüfung eines Gesuches Erforderliche", "ZIELGRUPPE": "Einwohnerinnen und Einwohnern, Bürgerinnen und Bürger von Uitikon und Personen, die in einer besonderen Beziehung zur Gemeinde stehen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (160, 'stiftung-walter-und-anne-marie-boveri', 'Stiftung Walter und Anne Marie Boveri', 91, 'Die Stiftung erbringt Leistungen für unterstützungsbedürftige Kinder und Jugendliche bis 25 Jahre. Sie gewährt Hilfeleistungen für Drogenkranke, insbesondere im Zusammenhang mit therapeutischen Vorkehrungen. Die Stiftung unterstützt konkrete Projekte, die den Leistungsempfängern direkt zugute kommen. Sie leistet jedoch keine Betriebsbeiträge. Gesuche von Privatpersonen werden nicht berücksichtigt.', 'c/o Dr. iur. Barbara Ganz - Sekretariat, Greifenseestrasse 58, 8603 Schwerzenbach, 043 541 19 31, stiftung.boveri@gmail.com', 'c/o Dr. iur. Barbara Ganz - Sekretariat, Greifenseestrasse 58, 8603 Schwerzenbach', '8603', 'Schwerzenbach', '["043 541 19 31"]', '["stiftung.boveri@gmail.com"]', '["gmail.com"]', 'Jugend & Familie, Kranke, Ausbildung', 'Institutionen', 'Ganzes Jahr', 'Unterlagen per Post und elektronisch an das Sekretariat.', 'Ausbildungsbestätigung, Kontoangaben, Jahresrechnung, Jahresbericht, Revisionsbericht, Projektbeschreibung, Kostenvoranschlag, Finanzierungsplan', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Jahresrechnung, Jahresbericht, Revisionsbericht, Projektbeschreibung, Kostenvoranschlag, Finanzierungsplan", "ZIELGRUPPE": "Jugend & Familie, Kranke, Ausbildung", "EMPFANGSSTELLE": "Unterlagen per Post und elektronisch an das Sekretariat.", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (161, 'stiftung-wfjb-wohnraum-fur-jungere-m-mit-behinderungen', 'Stiftung WFJB – Wohnraum für jüngere M. mit Behinderungen', 91, 'Der Zweck der Stiftung besteht in der Förderung von Wohnangeboten für jüngere Menschen mit Behinderungen und chronischkranke Menschen in der ganzen Schweiz. Die Betroffenen dürfen sich nicht im AHV-Alter befinden. Die Stiftung kann Liegenschaften erwerben oder mieten und für den genannten Zweck bauen oder umbauen. Für die Betriebsführung dieser Wohnangebote können lokale bzw. regionale Trägerschaften errichtet werden. Diese Trägerschaften sollten wenn möglich auch die Verträge der erworbenen oder gemieteten Liegenschaften übernehmen.', 'Alte Landstrasse 9, 8942 Oberrieden, 044 720 19 22, info@wfjb.ch, www.wfjb.ch', 'Alte Landstrasse 9, 8942 Oberrieden,, www.', '8942', 'Oberrieden', '["044 720 19 22"]', '["info@wfjb.ch"]', '["wfjb.ch", "www.wfjb.ch"]', 'Jugend & Familie, Menschen mit Behinderungen, Kranke', 'Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie, Menschen mit Behinderungen, Kranke", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (162, 'stipendienstiftung-reiser-siemssen-selve-gerdtzen', 'Stipendienstiftung Reiser-Siemssen / Selve-Gerdtzen', 92, 'Stipendien für Studierende aus der Schweiz und Deutschland, welche an der Universität Zürich immatrikuliert sind, sehr gute Leistungen vorweisen und von den Eltern zu wenig unterstützt werden können.', 'c/o Universität Zürich Studienfinanzierung, Rämistrasse 71, 8006 Zürich, 044 634 22 04, www.studienfinanzierung.uzh.ch', 'c/o Universität Zürich Studienfinanzierung, Rämistrasse 71, 8006 Zürich', '8006', 'Zürich', '["044 634 22 04"]', '[]', '["www.studienfinanzierung.uzh.ch"]', 'Sehr gute Studierende der Universität Zürich mit Schweizer und Deutscher Nationalität', 'Privatpersonen', 'Spezialformular anfordern', 'Keine direkte Gesuchseingabe an die Stiftung möglich. Bitte allgemeine Gesuche um Studienfinanzierung an die Fachstelle Studienfinanzierung richten. Webformular unter www.studienfinanzierung.uzh.ch', 'Ausbildungsbestätigung, Kontoangaben, Referenzen', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen", "ZIELGRUPPE": "Sehr gute Studierende der Universität Zürich mit Schweizer und Deutscher Nationalität", "EMPFANGSSTELLE": "Keine direkte Gesuchseingabe an die Stiftung möglich. Bitte allgemeine Gesuche um Studienfinanzierung an die Fachstelle Studienfinanzierung richten. Webformular unter www.studienfinanzierung.uzh.ch", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (163, 'st-nikolausgesellschaft-der-stadt-zurich', 'St. Nikolausgesellschaft der Stadt Zürich', 77, 'Unterstützung von bedürftigen Menschen (Einzelne und Familien, Stadt Zürich), St. Nikolausfeiern, Clausbesuche. Samichlausumzug', 'Postfach, 8036 Zürich, 044 454 70 00, zentrale@samichlaus-zuerich.ch, www.samichlaus-zuerich.ch', 'Postfach, 8036 Zürich,, www.', '8036', 'Zürich', '["044 454 70 00"]', '["zentrale@samichlaus-zuerich.ch"]', '["samichlaus-zuerich.ch", "www.samichlaus-zuerich.ch"]', 'Jugend & Familie, Firmen', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, 'Referenzen', '{"BEILAGEN": "Referenzen", "ZIELGRUPPE": "Jugend & Familie, Firmen", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (164, 'swiss-life-ag-stiftung-perspektiven', 'Swiss Life AG – Stiftung «Perspektiven»', 92, 'Zweck der Stiftung ist die Förderung von gemeinnützigen Initiativen in den Bereichen Gesundheit, Wissenschaft, Bildung, Kultur und Sport.', 'General-Guisan-Quai 40, Postfach, 8022 Zürich, 043 284 77 55, info@swisslife.ch, www.swisslife.ch/perspektiven', 'General-Guisan-Quai 40, Postfach, 8022 Zürich,, www./perspektiven', '8022', 'Zürich', '["043 284 77 55"]', '["info@swisslife.ch"]', '["swisslife.ch", "www.swisslife.ch/perspektiven"]', 'Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen, Armut', 'Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie, Ältere Menschen, Menschen mit Behinderungen, Kranke, Ausländer/innen, Armut", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (165, 'swiss-re-foundation', 'Swiss Re Foundation', 93, 'Die Swiss Re Foundation spiegelt die sozialen und humanitären Werte der Swiss Re wider. Unsere Mission ist es, Gesellschaften aufzubauen, damit diese in der Lage sind, gesundheitlichen, ökologischen und wirtschaftlichen Risiken standzuhalten und sich davon rasch zu erholen. Wir tun dies dort, wo Swiss Re tätig ist oder dies in Zukunft sein will.', 'c/o Swiss Re Management Ltd, Mythenquai 50/60, 8002 Zürich, swissrefoundation@swissre.com, www.swissrefoundation.org', 'c/o Swiss Re Management Ltd, Mythenquai 50/60, 8002 Zürich', '8002', 'Zürich', '[]', '["swissrefoundation@swissre.com"]', '["swissre.com", "www.swissrefoundation.org"]', 'Eine Wohltätigkeitsorganisation muss die folgenden Kriterien erfüllen, um als «Charity of the Year» in Betracht zu kommen:
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (166, 'swo-docu-swiss-welfare-organisation', 'SWO-docu Swiss Welfare Organisation', 93, 'Dokumentiert und fördert Gemeinwesenprojekte in den Bereichen Umwelt und Ökologie, Gesundheit, Bildung und Schaffung von kleinsten Wirtschaftskreisläufen. Begünstigt werden Strassenkinder und deren Familien in Lateinamerika.', 'Stiftung für Strassenkinder, Strehlgasse 11, 8600 Dübendorf, 044 882 36 20, info@swo-docu.ch, www.swo-docu.ch', 'Stiftung für Strassenkinder, Strehlgasse 11, 8600 Dübendorf,, www.', '8600', 'Dübendorf', '["044 882 36 20"]', '["info@swo-docu.ch"]', '["swo-docu.ch", "www.swo-docu.ch"]', 'Jugend und Familie, Menschen mit Behinderungen, Soz. Institutionen, Ausländer/innen, Gesundheit, Armut, Ausbildung', 'Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Jugend und Familie, Menschen mit Behinderungen, Soz. Institutionen, Ausländer/innen, Gesundheit, Armut, Ausbildung", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (167, 'teamco-foundation-schweiz', 'Teamco Foundation Schweiz', 94, 'Die Teamco Foundation Schweiz unterstützt Projekte für Kinder, Jugendliche und Betagte. Gefördert werden vor allem Institutionen in der Schweiz, unterstützt werden zum Beispiel Projekte, die
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (168, 'tilber-stiftung', 'Tilber-Stiftung', 94, 'Zweck der Stiftung ist es, kranken Menschen zu helfen, in erster Linie durch Betreuung, Begleitung und Unterstützung Chronisch- und Schwerkranker, wenn keine anderen Kostenträger vorhanden sind.', 'Stadelhoferstrasse 18, 8001 Zürich', 'Stadelhoferstrasse 18, 8001 Zürich', '8001', 'Zürich', '[]', '[]', '[]', NULL, 'Privatpersonen', 'Ganzes Jahr', NULL, 'Arztzeugnis, Kontoangaben, Referenzen', '{"BEILAGEN": "Arztzeugnis, Kontoangaben, Referenzen", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (169, 'turkisch-islamische-stiftung-fur-die-schweiz', 'Türkisch-Islamische Stiftung für die Schweiz', 94, 'Die in der Schweiz lebenden türkischen Muslimen sollen geistig gefördert werden. Dem harmonischen Zusammenleben mit Nichtmuslimen soll dabei besondere Beachtung geschenkt werden.', 'Schwamendingenstrasse 102, 8050 Zürich, 044 242 77 4, 044 247 78 48, info@diyanet.ch, www.diyanet.ch', 'Schwamendingenstrasse 102, 8050 Zürich, 044 242 77 4,, www.', '8050', 'Zürich', '["044 247 78 48"]', '["info@diyanet.ch"]', '["diyanet.ch", "www.diyanet.ch"]', 'Ausländer/innen, Ausbildung, Armut', 'Privatpersonen, Institutionen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "Ausländer/innen, Ausbildung, Armut", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (170, 'ubs-mitarbeiter-helfen', 'UBS Mitarbeiter helfen', 95, 'UBS Mitarbeiter helfen ist ein politisch und konfessionell neutraler Verein, der sich durch Spenden und Mitgliederbeiträge von UBS-Mitarbeitenden und -Pensionierten finanziert. Sämtliche administrative Kosten des Vereins werden von UBS übernommen. 
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (171, 'ubs-stiftung-fur-soziales-und-ausbildung', 'UBS Stiftung für Soziales und Ausbildung', 95, 'Finanzielle Unterstützung von Projekten zur Förderung der Bildung, Qualifizierung und beruflichen Integration von Personen mit Benachteiligungen und/oder besonderen Lernbedürfnissen. Keine Unterstützung von Einzelpersonen.', 'Europaallee 21, Postfach, 8098 Zürich, 044 234 44 52 (Geschäftsstelle), sozialstiftung@ubs.com, www.ubs.com/sozialstiftung', 'Europaallee 21, Postfach, 8098 Zürich, (Geschäftsstelle), www./sozialstiftung', '8098', 'Zürich', '["044 234 44 52"]', '["sozialstiftung@ubs.com"]', '["ubs.com", "www.ubs.com/sozialstiftung"]', 'Gemeinnützige Organisationen und Projekte zugunsten von Personen mit sozialen, körperlichen, geistigen oder psychischen Benachteiligungen und/oder besonderen Lernbedürfnissen in der Schweiz. Keine Unterstützung von Einzelpersonen.', 'Institutionen', 'Ganzes Jahr Über die Unterstützung von Gesuchen entscheidet der Stiftungsrat im Rahmen seiner Frühlings- und Herbstsitzung. Spezialformular anfordern', 'Telefonische Kontaktaufnahme mit der Geschäftsstelle zwecks Vorabklärung wird empfohlen. Förderkriterien unter www.ubs.com/sozialstiftung', 'Begleitbrief. Vollständig ausgefülltes Gesuchformular (zum Download auf www.ubs.com/sozialstiftung). Detaillierte Projektbeschreibung (Inhalte, Zielgruppe, Ziele, Zeitplan etc.)  Bitte geben Sie an, für welches Teilprojekt bzw. für welche Anschaffu Anschaffung o.ä. die angefragten Mittel eingesetzt werden könnten. Detailliertes Projektbudget mit Finanzierungsplan: Kosten, Eigenleistungen, Erträge inkl. Übersicht über zugesprochene und beantragte Beiträge anderer Förderstellen (laufende Aktualisierung gewünscht). Informationen zur Trägerschaft (Jahresbericht, Jahresrechnung, Statuten, Steuerbefreiung, Handelsregisterauszug, o.ä.). Medienberichte falls vorhanden.', '{"BEILAGEN": "Begleitbrief. Vollständig ausgefülltes Gesuchformular (zum Download auf www.ubs.com/sozialstiftung). Detaillierte Projektbeschreibung (Inhalte, Zielgruppe, Ziele, Zeitplan etc.)  Bitte geben Sie an, für welches Teilprojekt bzw. für welche Anschaffu Anschaffung o.ä. die angefragten Mittel eingesetzt werden könnten. Detailliertes Projektbudget mit Finanzierungsplan: Kosten, Eigenleistungen, Erträge inkl. Übersicht über zugesprochene und beantragte Beiträge anderer Förderstellen (laufende Aktualisierung gewünscht). Informationen zur Trägerschaft (Jahresbericht, Jahresrechnung, Statuten, Steuerbefreiung, Handelsregisterauszug, o.ä.). Medienberichte falls vorhanden.", "ZIELGRUPPE": "Gemeinnützige Organisationen und Projekte zugunsten von Personen mit sozialen, körperlichen, geistigen oder psychischen Benachteiligungen und/oder besonderen Lernbedürfnissen in der Schweiz. Keine Unterstützung von Einzelpersonen.", "EMPFANGSSTELLE": "Telefonische Kontaktaufnahme mit der Geschäftsstelle zwecks Vorabklärung wird empfohlen. Förderkriterien unter www.ubs.com/sozialstiftung", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr Über die Unterstützung von Gesuchen entscheidet der Stiftungsrat im Rahmen seiner Frühlings- und Herbstsitzung. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (172, 'verena-boller-stiftung', 'Verena Boller Stiftung', 96, 'Unterstützung bedürftiger Kinder, Jugendlicher und älterer Menschen mit körperlicher oder geistiger Behinderung oder Krankheit', 'c/o Sigel Treuhand, Mühlebachstrasse 72, Postfach 158, 8032 Zürich, Tel. 079 678 20 71', 'c/o Sigel Treuhand, Mühlebachstrasse 72, Postfach 158, 8032 Zürich, Tel.', '8032', 'Zürich', '["079 678 20 71"]', '[]', '[]', 'Institutionen und Hilfswerke mit Sitz im Kanton Zürich', 'Privatpersonen, Institutionen', 'Ganzes Jahr jederzeit', 'Verena Boller Stiftung, Sigel Treuhand, Mühlebachstrasse 72, Postfach 158, 8032 Zürich', NULL, '{"ZIELGRUPPE": "Institutionen und Hilfswerke mit Sitz im Kanton Zürich", "EMPFANGSSTELLE": "Verena Boller Stiftung, Sigel Treuhand, Mühlebachstrasse 72, Postfach 158, 8032 Zürich", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr jederzeit"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (173, 'viktor-durrenberger-stiftung', 'Viktor Dürrenberger-Stiftung', 96, 'Unterstützung und Förderung von Pflegekindern schweizerischer Herkunft (insbesondere Ausbildungsbeiträge). Finanzielle Unterstützung von Institutionen, die schweizerische Pflegekinder betreuen. Die Gesuche werden in der Regel im Monat Juni behandelt. Sie sollten daher jeweils bis zum Ende des Vormonates eingereicht werden. Für Beitragsgesuche bitte das Formular des Amts für Jugend und Berufsberatung des Kantons Zürich benutzen.', 'c/o Aeberli Treuhand AG, Zimmergasse 17, Postfach, 8034 Zürich, 044 265 66 66, info@aeberli-treuhand.ch', 'c/o Aeberli Treuhand AG, Zimmergasse 17, Postfach, 8034 Zürich', '8034', 'Zürich', '["044 265 66 66"]', '["info@aeberli-treuhand.ch"]', '["aeberli-treuhand.ch"]', 'Jugend & Familie, Ausbildung', 'Privatpersonen, Institutionen', NULL, NULL, NULL, '{"ZIELGRUPPE": "Jugend & Familie, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen, Institutionen"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (174, 'vontobel-stiftung', 'Vontobel Stiftung', 96, 'Soziales: in Not geratene Einzelpersonen und Familien, wohnhaft in der Schweiz. Unterstützungsbeiträge, Überbrückungshilfen, keine Darlehen.
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (175, 'walder-stiftung-leben-und-wohnen-im-alter', 'Walder Stiftung - Leben und Wohnen im Alter', 97, 'Die Walder Stiftung fördert bauliche und soziale Projekte und Programme sowie angewandte, praxisorientierte Forschung, die die Stärkung der Lebensqualität im Alter zum Ziel haben. Neben der Projektförderung will die Walder Stiftung den Wissensaustausch und die Diskussion zu Altersthemen fördern. Dazu führt sie regelmässig Tagungen zu Themen durch, die Leben und Wohnen im Alter betreffen. In regelmässigen Abständen organisiert sie Projekt- und Ideenwettbewerbe, in denen sie innovative Projekte zum Leben und Wohnen im Alter prämiert.', 'Forchstrasse 145, 8032 Zürich, 058 451 51 69, info@walder-stiftung.ch, www.walder-stiftung.ch', 'Forchstrasse 145, 8032 Zürich,, www.', '8032', 'Zürich', '["058 451 51 69"]', '["info@walder-stiftung.ch"]', '["walder-stiftung.ch", "www.walder-stiftung.ch"]', 'Institutionen zum Wohl älterer Menschen', 'Institutionen', 'Ganzes Jahr. Viermal jährlich wird über die Gesuche entschieden. Spezialformular anfordern', NULL, 'Detailliertes Budget, letzte Jahresrechnung, Liste der Gesuche an andere Förderstellen', '{"BEILAGEN": "Detailliertes Budget, letzte Jahresrechnung, Liste der Gesuche an andere Förderstellen", "ZIELGRUPPE": "Institutionen zum Wohl älterer Menschen", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Viermal jährlich wird über die Gesuche entschieden. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (176, 'walter-bachofner-stiftung', 'Walter Bachofner-Stiftung', 98, 'Die Walter Bachofner Stiftung unterstützt kirchliche, kulturelle, gemeinnützige oder wohltätige Projekte in der Gemeinde Fehraltorf und Umgebung und leistet damit einen positiven Beitrag zur Förderung der einheimischen Dorfkultur.', 'c/o Zürcher Kantonalbank, Grundstrasse 2, 8320 Fehraltorf, 044 956 61 33, raphael.reichenbach@zkb.ch', 'c/o Zürcher Kantonalbank, Grundstrasse 2, 8320 Fehraltorf', '8320', 'Fehraltorf', '["044 956 61 33"]', '["raphael.reichenbach@zkb.ch"]', '["zkb.ch"]', 'Allgemeinbevölkerung von Fehraltorf & Umgebung', 'Privatpersonen, Institutionen', 'Ganzes Jahr. Spezialformular anfordern', NULL, 'Projektbeschreibung', '{"BEILAGEN": "Projektbeschreibung", "ZIELGRUPPE": "Allgemeinbevölkerung von Fehraltorf & Umgebung", "GESUCHSTELLENDE": "Privatpersonen, Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (177, 'walter-und-gertrud-siegenthaler-stiftung', 'Walter und Gertrud Siegenthaler Stiftung', 98, 'Die im Jahr 2003 gegründete Stiftung hat zum Ziel, den akademischen Nachwuchs im Bereich der Medizin an der Universität Zürich zu fördern.', 'c/o UZH Foundation, Culmannstrasse 1, 8006 Zürich, 044 634 61 89, rahel.peter@uzhfoundation.ch, www.med.uzh.ch  Stiftungen und Preise / Grants  Siegenthaler Stiftung', 'c/o UZH Foundation, Culmannstrasse 1, 8006 Zürich,, Stiftungen und Preise / Grants Siegenthaler Stiftung', '8006', 'Zürich', '["044 634 61 89"]', '["rahel.peter@uzhfoundation.ch"]', '["uzhfoundation.ch", "www.med.uzh.ch"]', 'Akademischer Nachwuchs im Bereich der Medizin an der Universität', 'Privatpersonen', 'Spezialformular anfordern', NULL, 'Ausbildungsbestätigung, Referenzen, siehe Webseite', '{"BEILAGEN": "Ausbildungsbestätigung, Referenzen, siehe Webseite", "ZIELGRUPPE": "Akademischer Nachwuchs im Bereich der Medizin an der Universität", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Spezialformular anfordern"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (178, 'wilhelm-stunzi-stiftung', 'Wilhelm-Stünzi-Stiftung', 98, 'Eine Stiftung, deren Zinsen dazu dienen sollen, Söhnen und Töchtern von in Horgen wohnhafter bedürftiger Bürger oder Niedergelassenen die Erlernung eines Berufes oder das Studium zu erleichtern. Dabei sollen Bürger von Horgen vorzugsweise berücksichtigt werden.', 'c/o Soziales Horgen, Alte Landstrasse 25 Postfach, 8810 Horgen, 044 728 42 57, mara.aquilone@horgen.ch', 'c/o Soziales Horgen, Alte Landstrasse 25 Postfach, 8810 Horgen', '8810', 'Horgen', '["044 728 42 57"]', '["mara.aquilone@horgen.ch"]', '["horgen.ch"]', 'Jugend & Familie, Ausländer/innen, Ausbildung', 'Privatpersonen', 'Ganzes Jahr', NULL, 'Ausbildungsbestätigung, Kontoangaben, Referenzen, Angaben über finanzielle Verhältnisse (Vermögen, Einkommen)', '{"BEILAGEN": "Ausbildungsbestätigung, Kontoangaben, Referenzen, Angaben über finanzielle Verhältnisse (Vermögen, Einkommen)", "ZIELGRUPPE": "Jugend & Familie, Ausländer/innen, Ausbildung", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (179, 'willy-muller-forderstiftung', 'Willy Müller Förderstiftung', 99, 'Fördert geeignete Personen zwischen 18 und 40 Jahren bei der Ausbildung, beruflichen Umschulung oder Weiterbildung in Handwerk, Gewerbe und Dienstleistungsberufen und beim Gang in die Selbstständigkeit. Förderung durch Stipendien und Darlehen in Ergänzung zu selber beschafften Mitteln.', 'Sekretariat, Felseneggweg 4, 8134 Adliswil, 043 545 29 29 (Sekretariat), 044 202 50 22 (Geschäftssitz, Gerechtigkeitsgasse 23, 8001 Zürich), mail@willy-mueller-foerderstiftung.ch, www.willy-mueller-foerderstiftung.ch', 'Sekretariat, Felseneggweg 4, 8134 Adliswil, (Sekretariat), (Geschäftssitz, Gerechtigkeitsgasse 23, 8001 Zürich), www.', '8134', 'Adliswil', '["043 545 29 29", "044 202 50 22"]', '["mail@willy-mueller-foerderstiftung.ch"]', '["willy-mueller-foerderstiftung.ch", "www.willy-mueller-foerderstiftung.ch"]', 'Personen, unabhängig von Geschlecht, Herkunft und Religion zwischen dem 18. und 40. Altersjahr mit mindestens zweijährigem Wohnsitz in der Schweiz. Keine Unterstützung für akademische Studien. Keine Unterstützung an Organisationen. Es werden nur Individuen ihrer Ausbildung, beruflichen Umschulung oder Weiterbildung in Handwerk, Gewerbe und Dienstleistungsberufen und beim Gang in die Selbstständigkeit. Förderung durch Stipendien und Darlehen in Ergänzung zu selber beschafften Mitteln unterstützt.', 'Privatpersonen', 'Ganzes Jahr.Über online Antrag mit umgehender Empfangsbestätigung und Bearbeitung innerhalb von 60 Tagen', 'Willy Müller Förderstiftung, Sekretariat, Felseneggweg 4, 8134 Adliswil', 'Ausbildungsbestätigung, Antragsformular online auf www.willy-mueller-foerderstiftung.ch unter «Gesuch stellen». Weitere Unterlagen gemäss Antragsformular innerhalb von 10 Tagen per Post oder E-Mail nachreichen.', '{"BEILAGEN": "Ausbildungsbestätigung, Antragsformular online auf www.willy-mueller-foerderstiftung.ch unter «Gesuch stellen». Weitere Unterlagen gemäss Antragsformular innerhalb von 10 Tagen per Post oder E-Mail nachreichen.", "ZIELGRUPPE": "Personen, unabhängig von Geschlecht, Herkunft und Religion zwischen dem 18. und 40. Altersjahr mit mindestens zweijährigem Wohnsitz in der Schweiz. Keine Unterstützung für akademische Studien. Keine Unterstützung an Organisationen. Es werden nur Individuen ihrer Ausbildung, beruflichen Umschulung oder Weiterbildung in Handwerk, Gewerbe und Dienstleistungsberufen und beim Gang in die Selbstständigkeit. Förderung durch Stipendien und Darlehen in Ergänzung zu selber beschafften Mitteln unterstützt.", "EMPFANGSSTELLE": "Willy Müller Förderstiftung, Sekretariat, Felseneggweg 4, 8134 Adliswil", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr.Über online Antrag mit umgehender Empfangsbestätigung und Bearbeitung innerhalb von 60 Tagen"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (180, 'winterhilfe-zurich', 'Winterhilfe Zürich', 99, 'Die Winterhilfe Zürich bietet Menschen, die im Kanton Zürich wohnhaft und armutsbetroffen / armutsgefährdet sind, einerseits ihre regulären Angebote, wie finanzielle Unterstützung, Kleiderpakete, Betten- und Bettwaren (Neuware), Schulthek- und Kindergarten-Sets (Neuware) sowie Unterstützung für Kinder-Hobbys. Andererseits organisiert die Winterhilfe auch saisonale Aktionen für Menschen mit schmalem Budget. Gesuche für diese Aktionen werden ausschliesslich im Zeitraum angenommen, wenn diese auf der Website der Winterhilfe publiziert sind - zh.winterhilfe.ch/hilfe-erhalten. 
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (181, 'wohnstiftung-imfeldsteig-fur-alleinstehende-frauen', 'Wohnstiftung Imfeldsteig für alleinstehende Frauen', 100, 'Zweck der Stiftung ist es, allein stehenden Frauen im Kanton Zürich geeignete Wohnungen zu mässigen Mietzinsen zur Verfügung zu stellen.', '8001 Zürich, 044 212 35 00, wohnstiftungimfeldsteig@gmail.com, www.wohnstiftungimfeldsteig.com', '8001 Zürich', '8001', 'Zürich', '["044 212 35 00"]', '["wohnstiftungimfeldsteig@gmail.com"]', '["gmail.com", "www.wohnstiftungimfeldsteig.com"]', 'alleinstehende Frauen (auch mit Kindern)', 'Privatpersonen', 'Ganzes Jahr', NULL, NULL, '{"ZIELGRUPPE": "alleinstehende Frauen (auch mit Kindern)", "GESUCHSTELLENDE": "Privatpersonen", "EINREICHUNGSTERMIN": "Ganzes Jahr"}', NULL, 'Fonds und Stiftungsverzeichnis_2024_25.docx');
