INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (183, 'zurcher-stiftung-fur-psychisch-gesundheit-krankheit', 'Zürcher Stiftung für psychisch Gesundheit/Krankheit', 100, 'Finanzielle Hilfe in Einmalzahlung für bedürftige psychisch Kranke, die ihren Wohn- oder Heimatort im Kanton Zürich haben. Einzelpersonen sollen ihr Gesuch wenn möglich über eine Sozialberatungsstelle einreichen. In Ausnahmefällen kann eine finanzielle Unterstützung von Angehörigen psychisch Kranker gewährt werden. Projekte oder Handgelder von Kliniken im Kanton Zürich können finanziell mitgetragen werden, wenn sie direkt psychisch Kranken zugute kommen.', 'Schlösslistrasse 8, 8618 Oetwil am See, 044 929 84 42 (Markus Felss, Präsident), markus.felss@clienia.ch, www.zsfpk.ch', 'Schlösslistrasse 8, 8618 Oetwil am See, (Markus Felss, Präsident)', '8618', 'Oetwil am See', '["044 929 84 42"]', '["markus.felss@clienia.ch"]', '["clienia.ch", "www.zsfpk.ch"]', 'Bedürftige psychisch Kranke mit Wohn- oder Heimatort im Kanton Zürich
INSERT INTO public.organizations (id, org_key, name, page_start, description, contact_raw, address, postal_code, city, phone_numbers_jsonb, emails_jsonb, websites_jsonb, target_group_raw, applicants_raw, submission_deadline_raw, submission_address_raw, attachments_raw, raw_sections_jsonb, parse_warning, source_file) VALUES (1, 'accentus-stiftung', 'Accentus Stiftung', 31, 'Dachstiftung für soziale, ökologische, kulturelle und wissenschaftliche Projekte', 'Uetlibergstrasse 231, 8070 Zürich, 044 333 03 33, info@accentus.ch, www.accentus.ch', 'Uetlibergstrasse 231, 8070 Zürich,, www.', '8070', 'Zürich', '["044 333 03 33"]', '["info@accentus.ch"]', '["accentus.ch", "www.accentus.ch"]', 'Institutionen, Organisationen', 'Institutionen', 'Ganzes Jahr. Eingehende Anfragen an ACCENTUS werden laufend behandelt. Die Dachstiftung fördert ausschliesslich gemeinnützige und steuerbefreite Institutionen mit Sitz in der Schweiz. Vergabungskommissionen tagen in der Regel ein- bis dreimal jährlich. Der Stiftungsrat befindet zweimal pro Jahr (Frühjahr und Herbst) über Projektgesuche. Spezialformular anfordern', '', '', '{"ZIELGRUPPE": "Institutionen, Organisationen", "GESUCHSTELLENDE": "Institutionen", "EINREICHUNGSTERMIN": "Ganzes Jahr. Eingehende Anfragen an ACCENTUS werden laufend behandelt. Die Dachstiftung fördert ausschliesslich gemeinnützige und steuerbefreite Institutionen mit Sitz in der Schweiz. Vergabungskommissionen tagen in der Regel ein- bis dreimal jährlich. Der Stiftungsrat befindet zweimal pro Jahr (Frühjahr und Herbst) über Projektgesuche. Spezialformular anfordern"}', '', 'Fonds und Stiftungsverzeichnis_2024_25.docx');
